import type { VisualSummary } from '../types/visual-summary';

export function parseVisualSummary(summary: unknown): VisualSummary | null {
  if (!summary || typeof summary !== 'object') return null;
  const value = summary as VisualSummary;
  if (!value.range || typeof value.range.start !== 'number' || typeof value.range.end !== 'number') return null;
  return JSON.parse(JSON.stringify(value));
}

export function formatVisualSummaryForHistory(summary: VisualSummary): string {
  const lines = [
    `【可视化总结】${summary.title}`,
    `楼层范围：${summary.range.start}-${summary.range.end}`,
    `时间：${summary.time || '未记录'}`,
    `地点：${summary.location || '未记录'}`,
    '',
    '【剧情概览】',
    summary.overview || '未记录',
    '',
    '【重要事件】',
    ...(summary.events.length ? summary.events.map((item, index) => `${index + 1}. ${item}`) : ['未记录']),
    '',
    '【角色状态】',
    ...(summary.characters.length
      ? summary.characters.map(
          item =>
            `- ${item.name || '未知角色'}｜状态：${item.status || '未记录'}｜态度：${item.attitude || '未记录'}｜记忆：${item.memory || '未记录'}`,
        )
      : ['未记录']),
    '',
    '【关系变化】',
    ...(summary.relationshipChanges.length
      ? summary.relationshipChanges.map(
          item =>
            `- ${item.from || '未知'} -> ${item.to || '未知'}：${item.change || '未记录'}（${item.reason || '未记录'}）`,
        )
      : ['未记录']),
    '',
    '【伏笔】',
    ...(summary.foreshadowing.length ? summary.foreshadowing.map(item => `- ${item}`) : ['未记录']),
    '',
    '【待跟进】',
    ...(summary.todo.length ? summary.todo.map(item => `- ${item}`) : ['未记录']),
  ];
  return lines.join('\n');
}

/**
 * 「记忆主干」精简渲染：只保留最关键的常驻信息，用于蓝灯每轮注入的大总结，大幅省 token。
 *
 * 保留：概览、角色一句话速览（名字+状态）、未决事项（伏笔/待跟进）。
 * 省略：重要事件明细、角色态度/记忆长文、关系变化原因、时间/地点——
 *       这些细节保留在完整版里（formatVisualSummaryForHistory），等这条大总结转绿灯后，
 *       被相关关键词唤醒时再给出完整内容，因此不会丢失记忆，只是平时不占 token。
 */
export function formatVisualSummaryBackbone(summary: VisualSummary): string {
  const lines: string[] = [`【记忆主干】${summary.title}（楼层${summary.range.start}-${summary.range.end}）`];

  if (summary.overview) {
    lines.push('', '【概览】', summary.overview);
  }

  const chars = (summary.characters || []).filter(c => c?.name);
  if (chars.length) {
    lines.push('', '【角色速览】', chars.map(c => `${c.name}（${c.status || '—'}）`).join('；'));
  }

  const open = [...(summary.foreshadowing || []), ...(summary.todo || [])].filter(item => item && item !== '未记录');
  if (open.length) {
    lines.push('', '【未决/待跟进】', ...open.map(item => `- ${item}`));
  }

  return lines.join('\n');
}

export function formatVisualSummaryAsMarkdown(summary: VisualSummary): string {
  const list = (items: string[]) => (items.length ? items.map(item => `- ${item}`).join('\n') : '- 未记录');
  const characters = summary.characters.length
    ? summary.characters
        .map(item =>
          [
            `### ${item.name || '未知角色'}`,
            `- 状态：${item.status || '未记录'}`,
            `- 态度：${item.attitude || '未记录'}`,
            `- 记忆：${item.memory || '未记录'}`,
          ].join('\n'),
        )
        .join('\n\n')
    : '未记录';
  const relations = summary.relationshipChanges.length
    ? summary.relationshipChanges
        .map(item => `- ${item.from || '未知'} -> ${item.to || '未知'}：${item.change || '未记录'}（${item.reason || '未记录'}）`)
        .join('\n')
    : '- 未记录';
  const candidates = summary.worldbookCandidates.length
    ? summary.worldbookCandidates
        .map(item => `- [${item.enabled ? 'x' : ' '}] ${item.title || '未命名'}（${item.type}）：${item.content || '未填写'}`)
        .join('\n')
    : '- 未记录';

  return [
    `# ${summary.title || `可视化总结 ${summary.range.start}-${summary.range.end}`}`,
    '',
    `- 楼层：${summary.range.start}-${summary.range.end}`,
    `- 时间：${summary.time || '未记录'}`,
    `- 地点：${summary.location || '未记录'}`,
    '',
    '## 剧情概览',
    summary.overview || '未记录',
    '',
    '## 重要事件',
    list(summary.events),
    '',
    '## 角色状态',
    characters,
    '',
    '## 关系变化',
    relations,
    '',
    '## 伏笔',
    list(summary.foreshadowing),
    '',
    '## 待跟进',
    list(summary.todo),
    '',
    '## 世界书候选',
    candidates,
  ].join('\n');
}

/**
 * 从「已格式化的完整大总结文本」里现算一份精简主干（用于存量条目的兜底）。
 *
 * 存量大总结是旧版本创建的，extra 里没有 backbone_content。一键整理时对这类主干条目，
 * 用这个函数从它的完整文本反解析出概览、角色速览、未决事项，压成精简主干省 token。
 * 依赖 formatVisualSummaryForHistory 的固定小标题。解析失败时返回原文（不省但不丢）。
 */
export function backboneFromFormattedText(content: string): string {
  if (!content || typeof content !== 'string') return content;
  const lines = content.split('\n');

  // 标题行（第一行 "【可视化总结】xxx" + 楼层范围）
  const titleLine = lines[0] || '';
  const rangeLine = lines.find(l => l.startsWith('楼层范围：')) || '';

  const getSection = (header: string): string[] => {
    const out: string[] = [];
    let inSec = false;
    for (const raw of lines) {
      const line = raw.trim();
      if (line === header) {
        inSec = true;
        continue;
      }
      if (inSec) {
        if (/^【.+】/.test(line)) break; // 到下一小节结束
        if (line) out.push(line);
      }
    }
    return out;
  };

  const overview = getSection('【剧情概览】').filter(l => l !== '未记录');
  // 角色状态行形如：- 名字｜状态：xxx｜态度：...｜记忆：... → 只取 名字（状态）
  const chars = getSection('【角色状态】')
    .filter(l => l.startsWith('-') && l !== '- 未记录')
    .map(l => {
      const body = l.replace(/^-\s*/, '');
      const parts = body.split('｜');
      const name = (parts[0] || '').trim();
      const statusPart = parts.find(p => p.startsWith('状态：'));
      const status = statusPart ? statusPart.replace('状态：', '').trim() : '';
      return status ? `${name}（${status}）` : name;
    })
    .filter(Boolean);
  const open = [...getSection('【伏笔】'), ...getSection('【待跟进】')].filter(l => l.startsWith('-') && l !== '- 未记录');

  const backboneTitle = titleLine.replace('【可视化总结】', '【记忆主干】');
  const out: string[] = [rangeLine ? `${backboneTitle}（${rangeLine.replace('楼层范围：', '楼层')}）` : backboneTitle];
  if (overview.length) out.push('', '【概览】', ...overview);
  if (chars.length) out.push('', '【角色速览】', chars.join('；'));
  if (open.length) out.push('', '【未决/待跟进】', ...open);

  const result = out.join('\n');
  // 没能压出任何有效内容就返回原文，避免把主干搞丢
  return result.trim().split('\n').length > 1 ? result : content;
}

/**
 * 从「历史总结的文本内容」里解析出伏笔 / 待跟进两段列表。
 * 用于没有结构化 visual_summary、只有格式化文本时的兜底提取。
 * 依赖 formatVisualSummaryForHistory 的固定小标题「【伏笔】」「【待跟进】」。
 */
export function extractOpenItemsFromText(content: string): { foreshadowing: string[]; todo: string[] } {
  const result = { foreshadowing: [] as string[], todo: [] as string[] };
  if (!content || typeof content !== 'string') return result;
  const lines = content.split('\n');
  let section: 'foreshadowing' | 'todo' | null = null;
  for (const raw of lines) {
    const line = raw.trim();
    if (line.startsWith('【伏笔】')) {
      section = 'foreshadowing';
      continue;
    }
    if (line.startsWith('【待跟进】')) {
      section = 'todo';
      continue;
    }
    // 遇到下一个【小节标题】就结束当前段
    if (/^【.+】$/.test(line)) {
      section = null;
      continue;
    }
    if (section && line.startsWith('- ')) {
      const item = line.slice(2).trim();
      if (item && item !== '未记录') result[section].push(item);
    }
  }
  return result;
}
