/**
 * 🔄 强制刷新插件样式表，绕开浏览器对 dist/style.css 的强缓存。
 *
 * SillyTavern 用固定 URL 的 <link> 加载 dist/style.css，该 URL 没有版本戳，
 * 浏览器会长期缓存。组件的 <style scoped> 会被编译进这个 style.css，并依赖
 * data-v-xxx 属性匹配；每次发版 data-v 哈希都会变，但缓存的旧 style.css 还是
 * 旧哈希，导致新 DOM 匹配不上旧规则，出现“卡片/间距全丢、样式错乱”的现象。
 *
 * 这里在启动时给该 <link> 的 href 追加当前版本号作为查询参数，强制重新下载，
 * 保证样式表与当前 JS（同样带版本戳）版本一致。
 */
function refreshPluginStylesheet() {
  try {
    const links = Array.from(document.querySelectorAll<HTMLLinkElement>('link[rel="stylesheet"]'));
    // 匹配本插件的样式表：URL 里同时包含本插件目录名与 style.css
    const candidates = links.filter(link => /maomaomz/i.test(link.href) && /style\.css/i.test(link.href));
    candidates.forEach(link => {
      const url = new URL(link.href, window.location.href);
      if (url.searchParams.get('v') === CURRENT_VERSION) return; // 已是当前版本，避免重复刷新
      url.searchParams.set('v', CURRENT_VERSION);
      link.href = url.toString();
      console.log('🔄 已为插件样式表追加版本戳，强制刷新缓存:', link.href);
    });
  } catch (e) {
    console.warn('⚠️ 刷新插件样式表失败（忽略）:', e);
  }
}

if (typeof window !== 'undefined') {
  refreshPluginStylesheet();
}

const evaluateSummaryTrigger = (lastMessageId: number, startId: number, interval: number) => {
  const safeInterval = Number.isFinite(interval) ? Math.max(1, Math.floor(interval)) : 1;
  const relativePosition = lastMessageId - startId;

  if (lastMessageId < startId) {
    return { relativePosition, shouldTrigger: false };
  }

  return {
    relativePosition,
    shouldTrigger: relativePosition >= safeInterval - 1,
  };
};

/**
 * 鲁棒地拿到酒馆事件系统的 { on, eventTypes }。
 *
 * 不同酒馆版本/环境暴露事件系统的位置不一样：
 * - TavernHelper.eventOn + window.tavern_events
 * - SillyTavern.eventSource + SillyTavern.eventTypes
 * - SillyTavern.getContext().eventSource + .eventTypes（QR2 等插件走这条）
 * 之前只判前两种，导致部分环境「事件系统不可用」、所有监听都没挂上。这里把三种都覆盖。
 */
function getEventBus(): { on: (event: string, cb: (...args: any[]) => void) => void; types: any } | null {
  const w = window as any;
  // 1) TavernHelper
  try {
    if (typeof w.TavernHelper?.eventOn === 'function' && w.tavern_events) {
      return { on: (e, cb) => w.TavernHelper.eventOn(e, cb), types: w.tavern_events };
    }
  } catch {
    /* ignore */
  }
  // 2) SillyTavern.eventSource
  try {
    const st = typeof SillyTavern !== 'undefined' ? (SillyTavern as any) : w.SillyTavern;
    if (st?.eventSource?.on && st?.eventTypes) {
      return { on: (e, cb) => st.eventSource.on(e, cb), types: st.eventTypes };
    }
    // 3) SillyTavern.getContext().eventSource（QR2 等插件实际使用的路径）
    const ctx = typeof st?.getContext === 'function' ? st.getContext() : null;
    if (ctx?.eventSource?.on && (ctx.eventTypes || ctx.event_types)) {
      return { on: (e, cb) => ctx.eventSource.on(e, cb), types: ctx.eventTypes || ctx.event_types };
    }
  } catch {
    /* ignore */
  }
  return null;
}

type HiddenMessageRecord = { message_id: number; name: string; role: string; message: string };
let isRestoringHiddenMessages = false;

function getHiddenMessagesStorageKey(): string | null {
  const scriptId = getScriptIdSafe();
  const chatId = getChatIdSafe();
  return scriptId && chatId ? `${scriptId}_hidden_messages_${chatId}` : null;
}

// 自动隐藏也必须留下与手动隐藏相同的聊天级记录；酒馆重新加载聊天时会重建消息状态。
function rememberAutoHiddenMessages(messageIds: number[]) {
  const storageKey = getHiddenMessagesStorageKey();
  if (!storageKey || messageIds.length === 0) return;

  try {
    const saved = localStorage.getItem(storageKey);
    const records: HiddenMessageRecord[] = saved ? JSON.parse(saved) : [];
    const knownIds = new Set(records.map(record => record.message_id));
    for (const message_id of messageIds) {
      if (!knownIds.has(message_id)) {
        records.push({ message_id, name: '自动总结', role: 'system', message: '' });
      }
    }
    localStorage.setItem(storageKey, JSON.stringify(records));
    console.log(`💾 已记录 ${messageIds.length} 个自动隐藏楼层，供重新打开聊天后恢复`);
  } catch (e) {
    console.warn('保存自动隐藏楼层记录失败（忽略）:', e);
  }
}

// 2.0.357 之前的自动隐藏只改了酒馆当次内存状态，历史聊天没有恢复记录。
// 对每个旧聊天只回填一次，避免用户后来手动显示楼层后又被反复自动隐藏。
function backfillLegacyAutoHiddenMessages() {
  const storageKey = getHiddenMessagesStorageKey();
  if (!storageKey || localStorage.getItem(`${storageKey}_legacy_backfill_v1`)) return;

  try {
    const saved = localStorage.getItem(storageKey);
    const existing: HiddenMessageRecord[] = saved ? JSON.parse(saved) : [];
    if (Array.isArray(existing) && existing.length > 0) return;

    const settings = useSettingsStore().settings;
    if (settings.auto_hide_after_summary !== true) return;

    const latestSummaryEnd = useSummaryHistoryStore()
      .getSummaryHistory()
      .reduce((latest, item) => Math.max(latest, Number(item.end_id) || -1), -1);
    const keepRecent = Math.max(0, Math.floor(settings.keep_recent_messages || 0));
    const hideEndId = latestSummaryEnd - keepRecent;
    if (hideEndId < 0) return;

    rememberAutoHiddenMessages(Array.from({ length: hideEndId + 1 }, (_, message_id) => message_id));
    localStorage.setItem(`${storageKey}_legacy_backfill_v1`, '1');
    console.log(`🔁 已为旧版自动总结回填隐藏记录: 楼层 0-${hideEndId}`);
  } catch (e) {
    console.warn('回填旧版自动隐藏记录失败（忽略）:', e);
  }
}

async function restorePersistedHiddenMessages() {
  const storageKey = getHiddenMessagesStorageKey();
  const TH = (window as any).TavernHelper;
  if (!storageKey || typeof TH?.setChatMessages !== 'function' || isRestoringHiddenMessages) return;

  try {
    const saved = localStorage.getItem(storageKey);
    const records: HiddenMessageRecord[] = saved ? JSON.parse(saved) : [];
    const lastMessageId = TH.getLastMessageId?.();
    const messageIds = records
      .map(record => Number(record.message_id))
      .filter(message_id => Number.isInteger(message_id) && message_id >= 0 && (lastMessageId === undefined || message_id <= lastMessageId));
    if (messageIds.length === 0) return;

    // setChatMessages 会同步触发 CHAT_CHANGED；标记本次内部更新，防止事件监听再次恢复而死循环。
    isRestoringHiddenMessages = true;
    // 只恢复聊天数据中的隐藏标记，避免切换聊天后再次全量重绘聊天区。
    await TH.setChatMessages(messageIds.map(message_id => ({ message_id, is_hidden: true })), { refresh: 'none' });
    console.log(`🙈 已恢复当前聊天的 ${messageIds.length} 个隐藏楼层`);
  } catch (e) {
    console.warn('恢复隐藏楼层失败（忽略）:', e);
  } finally {
    isRestoringHiddenMessages = false;
  }
}

/**
 * 带自动重试的可视化总结（薄封装，复用 总结功能.ts 的通用重试）。
 */
async function summarizeVisualWithRetry(
  start: number,
  end: number,
  onAttempt?: (attempt: number, maxAttempts: number) => void,
  maxAttempts = 3,
) {
  // 带上「本段之前遗留的伏笔 / 待跟进」，让 AI 据本段剧情核对更新，避免旧条目无脑堆积
  let prior: { foreshadowing: string[]; todo: string[] } | undefined;
  try {
    prior = useSummaryHistoryStore().collectPriorOpenContext(start);
  } catch (e) {
    console.warn('收集过往伏笔/待跟进失败（忽略）:', e);
  }
  return withSummaryRetry(
    () => summarizeVisualMessages(start, end, prior),
    (attempt, max) => onAttempt?.(attempt, max),
    maxAttempts,
  );
}

