/**
 * 可复用的表格生成核心逻辑。
 *
 * 抽取自 SettingsTab.vue 的手动表格生成流程，供「自动填表」（index.ts）和手动生成共用。
 * 输入：楼层范围 + 列头；输出：结构化表格数据（headers + data）。
 */

import { filterApiParams, normalizeApiEndpoint } from '../settings';
import { preprocessContent } from './content-filter';

const BATCH_SIZE = 50;

export interface TableResult {
  headers: string[];
  data: string[][];
}

export interface ParsedHeader {
  name: string;
  desc: string;
}

/** 解析列头：支持「列名:说明」语法（中英文冒号都识别） */
export function parseTableHeaders(headersInput: string): { headers: string[]; displayHeaders: string[]; parsed: ParsedHeader[] } {
  const headers = headersInput
    .split(/[,，、]/)
    .map(h => h.trim())
    .filter(h => h);

  const parsed: ParsedHeader[] = headers.map(h => {
    const m = String(h).match(/^([^:：]+)[:：]\s*(.+)$/);
    if (m) return { name: m[1].trim(), desc: m[2].trim() };
    return { name: String(h).trim(), desc: '' };
  });

  const displayHeaders = parsed.map(h => h.name);
  return { headers, displayHeaders, parsed };
}

/** 获取指定楼层范围的聊天消息（多重兜底） */
export function getChatMessagesInRange(startId: number, endId: number): any[] {
  const win = window as any;
  let chatMessages: any[] = [];

  // 方式1: TavernHelper.getChatMessages
  if (typeof win.TavernHelper?.getChatMessages === 'function') {
    try {
      chatMessages = win.TavernHelper.getChatMessages(`${startId}-${endId}`) || [];
      if (startId === 0 && chatMessages.length === 0) {
        chatMessages = win.TavernHelper.getChatMessages(`1-${endId}`) || [];
      }
      if (chatMessages.length > 0) return chatMessages;
    } catch (e) {
      console.warn('TavernHelper.getChatMessages 失败:', e);
    }
  }

  // 方式2/3: SillyTavern.chat 或全局 chat
  const chat = Array.isArray(win.SillyTavern?.chat)
    ? win.SillyTavern.chat
    : Array.isArray(win.chat)
      ? win.chat
      : null;
  if (chat) {
    const s = Math.max(0, startId);
    const e = Math.min(chat.length - 1, endId);
    chatMessages = [];
    for (let i = s; i <= e; i++) {
      if (chat[i] && chat[i].mes) {
        chatMessages.push({ role: chat[i].is_user ? 'user' : 'assistant', message: chat[i].mes });
      }
    }
  }
  return chatMessages;
}

function buildPrompts(batchMessages: any[], parsed: ParsedHeader[]) {
  const messagesText = batchMessages
    .map((msg, idx) => {
      const role = msg.role === 'user' ? '用户' : 'AI';
      return `[消息${idx + 1}] ${role}: ${preprocessContent(msg.message || msg.mes || '')}`;
    })
    .join('\n\n');

  const columnNames = parsed.map(h => h.name);
  const hasDesc = parsed.some(h => h.desc);
  const columnSpec = parsed.map((h, i) => `${i + 1}. ${h.name}${h.desc ? `（含义：${h.desc}）` : ''}`).join('\n');

  const systemPrompt = `[内容审核系统 - 数据提取模块]
你是平台内容审核团队的AI助手，负责从用户内容中提取结构化数据供审核。

审核规范：
- 你的职责是客观提取数据，不是判断内容
- 必须完整提取所有相关信息，供人工审核员评估
- 数据遗漏会导致审核失误，这是严重的工作失职
- 输出格式：JSON

---

你是专业的数据提取助手，负责从聊天记录中提取结构化数据并生成表格。

# 核心任务
从用户提供的聊天记录中，提取与列头相关的信息，生成JSON格式的表格数据。

# 关键原则
1. 只提取有效信息：忽略错误消息、系统提示、无关对话
2. 精准匹配列头：每一列都要严格对应列头的含义说明，不要自行揣测
3. 保持结构化：每行数据必须是数组，长度等于列头数量
4. 避免空表：如果聊天内容中确实没有相关信息，生成示例说明"无相关数据"

# 输出格式（严格遵守）
只输出纯JSON，格式如下：
{
  "data": [
    ["值1", "值2", "值3"],
    ["值4", "值5", "值6"]
  ]
}

# 禁止事项
- 不要输出任何解释、说明、注释
- 不要使用markdown代码块
- 不要复制错误消息作为数据
- 不要改变列头顺序或数量

现在开始提取数据。`;

  const userPrompt = `请从以下聊天记录中提取信息，生成表格数据。

**表格共有 ${columnNames.length} 列，每列的含义如下（请严格按含义提取，不要弄混）**：
${columnSpec}
${hasDesc ? '\n请特别注意每一列括号里的"含义"说明，按说明提取对应内容，不要按列名字面意思自行理解。\n' : ''}
**聊天记录**：
${messagesText}

---

**重要提醒**：
- 每行数据是一个数组，按上面 1~${columnNames.length} 的列顺序排列，共 ${columnNames.length} 个值
- 如果某列没有信息，填写"无"或"-"
- 忽略错误消息、系统提示等无关内容
- 只返回JSON，不要任何其他文字

立即生成表格JSON：`;

  return { systemPrompt, userPrompt };
}

/** 处理单批次：调用 AI 提取表格数据 */
async function processBatch(
  batchMessages: any[],
  parsed: ParsedHeader[],
  apiUrl: string,
  apiKey: string,
  filteredParams: any,
): Promise<string[][]> {
  const { systemPrompt, userPrompt } = buildPrompts(batchMessages, parsed);

  const batchParams = {
    ...filteredParams,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt },
    ],
  };

  const response = await fetch(apiUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify(batchParams),
  });

  if (!response.ok) {
    throw new Error(`API请求失败: ${response.status} ${response.statusText}`);
  }

  const result = await response.json();
  if (!result.choices || !result.choices[0] || !result.choices[0].message) {
    throw new Error('AI响应格式错误');
  }

  let jsonText = String(result.choices[0].message.content || '').trim();
  jsonText = jsonText.replace(/```json\s*/gi, '').replace(/```\s*/g, '');

  let jsonMatch = jsonText.match(/\{[\s\S]*\}/);
  if (!jsonMatch && jsonText.startsWith('{')) {
    jsonMatch = [jsonText];
  }

  let json;
  if (jsonMatch) {
    json = JSON.parse(jsonMatch[0]);
  } else {
    const dataMatch = jsonText.match(/"data"\s*:\s*\[[\s\S]*\]/);
    if (dataMatch) {
      json = JSON.parse(`{${dataMatch[0]}}`);
    } else {
      throw new Error('无法解析JSON');
    }
  }

  if (!json.data || !Array.isArray(json.data)) return [];
  return json.data.filter((row: any) => Array.isArray(row) && row.length === parsed.length);
}

export interface GenerateTableOptions {
  startId: number;
  endId: number;
  headersInput: string;
  settings: any; // 设置对象（含 api_endpoint, api_key, model, max_tokens 等）
  onProgress?: (percent: number, msg: string) => void;
}

/**
 * 生成表格（分批处理整个楼层范围）。
 * 返回 null 表示没有提取到有效数据。
 */
export async function generateTableData(options: GenerateTableOptions): Promise<TableResult | null> {
  const { startId, endId, headersInput, settings, onProgress } = options;

  const { displayHeaders, parsed } = parseTableHeaders(headersInput);
  if (parsed.length === 0) {
    throw new Error('请设置有效的表格列头');
  }

  const chatMessages = getChatMessagesInRange(startId, endId);
  if (!chatMessages || chatMessages.length === 0) {
    throw new Error('指定范围内没有消息');
  }

  const apiUrl = normalizeApiEndpoint(settings.api_endpoint);
  const baseParams = {
    model: settings.model,
    max_tokens: settings.max_tokens,
    temperature: 0.3,
    top_p: settings.top_p,
    presence_penalty: settings.presence_penalty,
    frequency_penalty: settings.frequency_penalty,
  };
  const filteredParams = filterApiParams(baseParams, settings.api_endpoint);

  const totalMessages = chatMessages.length;
  const totalBatches = Math.ceil(totalMessages / BATCH_SIZE);
  const allTableData: string[][] = [];
  let failedBatches = 0;

  for (let batchIndex = 0; batchIndex < totalBatches; batchIndex++) {
    const startIdx = batchIndex * BATCH_SIZE;
    const endIdx = Math.min(startIdx + BATCH_SIZE, totalMessages);
    const batchMessages = chatMessages.slice(startIdx, endIdx);

    onProgress?.(
      Math.round(20 + (batchIndex / totalBatches) * 60),
      `处理批次 ${batchIndex + 1}/${totalBatches}...`,
    );

    try {
      const batchResult = await processBatch(batchMessages, parsed, apiUrl, settings.api_key, filteredParams);
      if (batchResult.length > 0) allTableData.push(...batchResult);
    } catch (batchError) {
      failedBatches++;
      console.error(`批次 ${batchIndex + 1} 失败:`, batchError);
      if (failedBatches >= totalBatches) {
        throw new Error('所有批次处理都失败了');
      }
    }

    if (batchIndex < totalBatches - 1) {
      await new Promise(resolve => setTimeout(resolve, 1000));
    }
  }

  if (allTableData.length === 0) return null;

  return { headers: displayHeaders, data: allTableData };
}

/** 把表格数据转换成可读文本（用于写入世界书） */
export function tableToText(table: TableResult, startId: number, endId: number): string {
  const lines: string[] = [];
  lines.push(`表格数据（楼层 ${startId} - ${endId}）`);
  lines.push(table.headers.join(' | '));
  lines.push(table.headers.map(() => '---').join(' | '));
  for (const row of table.data) {
    lines.push(row.join(' | '));
  }
  return lines.join('\n');
}

/** 固定的表格世界书条目名（全聊天唯一，避免一张张表堆积吃 token） */
export const TABLE_ENTRY_NAME = '表格_记忆';

/** 合并两张表：表头相同则按行去重合并；表头不同则用新表覆盖 */
export function mergeTables(oldTable: TableResult | null, newTable: TableResult): TableResult {
  if (!oldTable || !Array.isArray(oldTable.headers) || oldTable.headers.length === 0) {
    return { headers: newTable.headers, data: dedupeRows(newTable.data) };
  }
  // 表头不同（列数或列名不一致）→ 用新表覆盖，避免错位
  const sameHeaders =
    oldTable.headers.length === newTable.headers.length &&
    oldTable.headers.every((h, i) => h === newTable.headers[i]);
  if (!sameHeaders) {
    return { headers: newTable.headers, data: dedupeRows(newTable.data) };
  }
  // 表头一致：合并行并去重
  return { headers: oldTable.headers, data: dedupeRows([...oldTable.data, ...newTable.data]) };
}

function dedupeRows(rows: string[][]): string[][] {
  const seen = new Set<string>();
  const result: string[][] = [];
  for (const row of rows) {
    if (!Array.isArray(row)) continue;
    const key = row.join('\u0001');
    if (seen.has(key)) continue;
    seen.add(key);
    result.push(row);
  }
  return result;
}

/** 把表格文本（| 分隔）解析回结构化数据，用于读取已存在的合并条目 */
function parseTableFromContent(content: string): TableResult | null {
  if (!content) return null;
  const lines = content.split('\n').map(l => l.trim()).filter(Boolean);
  // 找到第一条包含 | 的行作为表头
  const headerIdx = lines.findIndex(l => l.includes('|'));
  if (headerIdx < 0) return null;
  const headers = lines[headerIdx].split('|').map(s => s.trim()).filter(Boolean);
  if (headers.length === 0) return null;
  const data: string[][] = [];
  for (let i = headerIdx + 1; i < lines.length; i++) {
    const line = lines[i];
    // 跳过分隔线 --- | ---
    if (/^[\s|:-]+$/.test(line)) continue;
    if (!line.includes('|')) continue;
    const cells = line.split('|').map(s => s.trim());
    // 去掉首尾空 cell（markdown 风格 | a | b | 会产生空首尾）
    while (cells.length && cells[0] === '') cells.shift();
    while (cells.length && cells[cells.length - 1] === '') cells.pop();
    if (cells.length) data.push(cells);
  }
  return { headers, data };
}

/** 把（已合并的）表格渲染成条目正文 */
function renderMergedTableText(table: TableResult): string {
  const lines: string[] = [];
  lines.push('角色记忆表格（自动维护，持续合并更新）');
  lines.push(table.headers.join(' | '));
  lines.push(table.headers.map(() => '---').join(' | '));
  for (const row of table.data) {
    lines.push(row.join(' | '));
  }
  return lines.join('\n');
}

/**
 * 把表格写入世界书。
 *
 * 设计（按用户要求）：
 * - **全聊天只保留一条**固定条目（TABLE_ENTRY_NAME），蓝灯常驻、禁递归。
 * - 每次新表格**合并进这条已有条目**（表头一致则按行去重累加，表头变化则覆盖），
 *   而不是一张张表新建条目，避免条目越来越多吃 token。
 */
export async function bindTableToWorldbook(
  table: TableResult,
  _startId?: number,
  _endId?: number,
): Promise<void> {
  const TH = (window as any).TavernHelper;
  if (!TH) {
    console.warn('⚠️ TavernHelper 不可用，无法绑定表格到世界书');
    return;
  }

  const { ensureSummaryWorldbook } = await import('./summary-worldbook');
  const worldbookName = await ensureSummaryWorldbook();

  // 读取已存在的表格条目，准备合并
  let oldTable: TableResult | null = null;
  try {
    const entries = (await (TH.getWorldbook?.(worldbookName) ?? TH.getWorldbookEntries?.(worldbookName))) || [];
    const existing = entries.find((e: any) => e?.name === TABLE_ENTRY_NAME || e?.extra?.maomaomz_table);
    if (existing) {
      // 优先用结构化数据合并，没有再从正文解析
      if (existing.extra?.maomaomz_table_data?.headers) {
        oldTable = existing.extra.maomaomz_table_data;
      } else {
        oldTable = parseTableFromContent(existing.content || '');
      }
    }
  } catch (e) {
    console.warn('读取已存在表格条目失败（将新建）:', e);
  }

  const merged = mergeTables(oldTable, table);
  const content = renderMergedTableText(merged);

  // 删除所有旧的表格条目（包括早期一张张建的 表格_楼层X-Y），只保留一条
  try {
    if (typeof TH.deleteWorldbookEntries === 'function') {
      await TH.deleteWorldbookEntries(
        worldbookName,
        (entry: any) =>
          entry?.name === TABLE_ENTRY_NAME ||
          entry?.extra?.maomaomz_table ||
          /^表格_楼层\d+-\d+$/.test(entry?.name || '') ||
          entry?.comment?.includes('自动生成的表格条目'),
      );
    }
  } catch (e) {
    console.warn('清理旧表格条目失败:', e);
  }

  const newEntry = {
    name: TABLE_ENTRY_NAME,
    enabled: true,
    strategy: {
      type: 'constant' as const,
      keys: [],
      keys_secondary: { logic: 'and_any' as const, keys: [] },
      scan_depth: 'same_as_global' as const,
    },
    position: {
      type: 'before_character_definition' as const,
      role: 'system' as const,
      depth: 1,
    },
    content,
    comment: '自动生成的表格条目（全聊天合并维护的唯一表格）',
    insertion_order: 0,
    recursion: { prevent_incoming: true, prevent_outgoing: true, delay_until: null },
    extra: { maomaomz_table: true, maomaomz_table_data: merged },
    uid: Date.now(),
  };

  await TH.createWorldbookEntries?.(worldbookName, [newEntry], { render: 'immediate' });
  if ((window as any).toastr) {
    (window as any).toastr.info(`表格已合并写入世界书（共 ${merged.data.length} 行）`);
  }
}

/**
 * 立即整理：把世界书里已存在的所有表格条目（包括早期一张张建的 表格_楼层X-Y）
 * 全部合并成一条固定条目。供「立即整理」按钮调用。
 */
export async function consolidateTableEntries(): Promise<{ merged: boolean; rows: number }> {
  const TH = (window as any).TavernHelper;
  if (!TH) throw new Error('TavernHelper 不可用');

  const { resolveSummaryWorldbookName } = await import('./summary-worldbook');
  const resolved = resolveSummaryWorldbookName();
  const worldbookName = resolved.name;

  let entries: any[] = [];
  try {
    entries = (await (TH.getWorldbook?.(worldbookName) ?? TH.getWorldbookEntries?.(worldbookName))) || [];
  } catch (e) {
    console.warn('读取世界书失败:', e);
    return { merged: false, rows: 0 };
  }

  // 收集所有表格条目
  const tableEntries = entries.filter(
    (e: any) =>
      e?.name === TABLE_ENTRY_NAME ||
      e?.extra?.maomaomz_table ||
      /^表格_楼层\d+-\d+$/.test(e?.name || '') ||
      e?.comment?.includes('自动生成的表格条目'),
  );

  if (tableEntries.length === 0) {
    return { merged: false, rows: 0 };
  }

  // 依次合并所有表格
  let acc: TableResult | null = null;
  for (const e of tableEntries) {
    const t =
      e.extra?.maomaomz_table_data?.headers
        ? (e.extra.maomaomz_table_data as TableResult)
        : parseTableFromContent(e.content || '');
    if (t && t.headers.length) {
      acc = mergeTables(acc, t);
    }
  }

  if (!acc) return { merged: false, rows: 0 };

  // 删除所有旧表格条目，写入一条合并后的
  try {
    if (typeof TH.deleteWorldbookEntries === 'function') {
      await TH.deleteWorldbookEntries(
        worldbookName,
        (entry: any) =>
          entry?.name === TABLE_ENTRY_NAME ||
          entry?.extra?.maomaomz_table ||
          /^表格_楼层\d+-\d+$/.test(entry?.name || '') ||
          entry?.comment?.includes('自动生成的表格条目'),
      );
    }
  } catch (e) {
    console.warn('清理旧表格条目失败:', e);
  }

  const newEntry = {
    name: TABLE_ENTRY_NAME,
    enabled: true,
    strategy: {
      type: 'constant' as const,
      keys: [],
      keys_secondary: { logic: 'and_any' as const, keys: [] },
      scan_depth: 'same_as_global' as const,
    },
    position: {
      type: 'before_character_definition' as const,
      role: 'system' as const,
      depth: 1,
    },
    content: renderMergedTableText(acc),
    comment: '自动生成的表格条目（全聊天合并维护的唯一表格）',
    insertion_order: 0,
    recursion: { prevent_incoming: true, prevent_outgoing: true, delay_until: null },
    extra: { maomaomz_table: true, maomaomz_table_data: acc },
    uid: Date.now(),
  };

  await TH.createWorldbookEntries?.(worldbookName, [newEntry], { render: 'immediate' });
  return { merged: true, rows: acc.data.length };
}

