/**
 * 智能唤醒（Smart Recall）
 *
 * 解决的问题：
 * 自动总结写入世界书的条目如果全部是「蓝灯（constant）」，会在**每一轮对话都注入提示词**，
 * 哪怕把对应楼层隐藏了也照样占 token，而且总结越来越多，token 只增不减。
 *
 * 思路：
 * - 最近的 N 条总结保持蓝灯（眼前剧情始终相关，需要常驻）。
 * - 更早的总结改成「绿灯（selective）」，并带上从总结里提取的关键词（角色名、地点等）。
 *   只有当这些关键词在最近对话里出现时，对应的旧总结才会被注入，否则休眠、零 token。
 *
 * 这样既保留了"想得起来"的能力（提到旧角色/旧地点会自动唤醒相关总结），
 * 又避免所有总结无脑常驻浪费 token。
 */

import type { VisualSummary } from '../types/visual-summary';
import { backboneFromFormattedText } from './visual-summary-format';

/**
 * 收集"不适合当唤醒锚点"的高频常驻名字：主角名、user 名。
 *
 * 这些名字几乎每轮对话都会出现，如果拿它们当绿灯关键词，旧总结会被每轮命中、
 * 等于没休眠——这正是"智能唤醒开了却感觉不到省 token"的主因。
 * 把它们从关键词里剔掉，绿灯条目才会真正在没提到旧角色/旧地点时休眠。
 */
export function getStopNames(): Set<string> {
  const stop = new Set<string>();
  const add = (v: any) => {
    const k = String(v ?? '').trim();
    if (k) stop.add(k.toLowerCase());
  };
  try {
    const st: any = typeof SillyTavern !== 'undefined' ? SillyTavern : (window as any).SillyTavern;
    const ctx = st && typeof st.getContext === 'function' ? st.getContext() : st;
    add(ctx?.name1); // user 名
    add(ctx?.name2); // 角色名（单人聊天时的主角）
  } catch {
    /* ignore */
  }
  try {
    const TH = (window as any).TavernHelper;
    const cur = TH?.getCharData?.('current');
    add(cur?.name);
  } catch {
    /* ignore */
  }
  return stop;
}

/**
 * 从可视化总结里提取用于绿灯唤醒的关键词。
 *
 * @param visual    可视化总结
 * @param stopNames 需要排除的高频常驻名字（主角/user 等）。不传则内部自动收集。
 */
export function extractRecallKeys(
  visual: VisualSummary | null | undefined,
  stopNames?: Set<string>,
): string[] {
  const stop = stopNames ?? getStopNames();
  const keys = new Set<string>();
  if (visual) {
    // 角色名（最重要的唤醒锚点）——主角/user 会被 addKey 里的 stop 过滤掉
    for (const c of visual.characters || []) {
      if (c?.name) addKey(keys, c.name, stop);
    }
    // 关系变化里的双方
    for (const r of visual.relationshipChanges || []) {
      if (r?.from) addKey(keys, r.from, stop);
      if (r?.to) addKey(keys, r.to, stop);
    }
    // 地点
    if (visual.location) {
      for (const part of String(visual.location).split(/[、,，/／\s]+/)) {
        addKey(keys, part, stop);
      }
    }
    // 世界书候选里的标题（地点/物品/设定名）
    for (const w of visual.worldbookCandidates || []) {
      if (w?.title) addKey(keys, w.title, stop);
    }
  }
  return Array.from(keys);
}

function addKey(set: Set<string>, raw: string, stop?: Set<string>) {
  const k = String(raw).trim();
  // 过滤无意义 / 过短 / 占位词
  if (!k) return;
  if (k.length < 2) return;
  if (['未知', '未记录', '无', '-', '未知角色', 'user', 'User', '你', '我'].includes(k)) return;
  // 过滤高频常驻名字（主角/user），否则绿灯每轮被命中形同蓝灯
  if (stop && stop.has(k.toLowerCase())) return;
  set.add(k);
}

/**
 * 从总结条目正文里兜底提取关键词（当条目没有存 extra.recall_keys 时使用）。
 * 解析 formatVisualSummaryForHistory 生成的「角色状态」「地点」行。
 */
export function extractRecallKeysFromContent(content: string, stopNames?: Set<string>): string[] {
  const stop = stopNames ?? getStopNames();
  const keys = new Set<string>();
  if (!content) return [];

  // 地点：地点：xxx
  const locMatch = content.match(/地点[:：]\s*(.+)/);
  if (locMatch) {
    for (const part of locMatch[1].split(/[、,，/／\s]+/)) addKey(keys, part, stop);
  }

  // 角色状态行：- 角色名｜状态：...
  const charLines = content.match(/^-\s*([^｜|]+)[｜|]/gm);
  if (charLines) {
    for (const line of charLines) {
      const m = line.match(/^-\s*([^｜|]+)[｜|]/);
      if (m) addKey(keys, m[1], stop);
    }
  }

  return Array.from(keys);
}

/** 判断条目是否是本插件创建的总结条目 */
export function isPluginSummaryEntry(entry: any): boolean {
  if (!entry) return false;
  if (entry.extra?.maomaomz_summary) return true;
  if (typeof entry.name === 'string' && /^总结_楼层\d+-\d+$/.test(entry.name)) return true;
  if (typeof entry.comment === 'string' && entry.comment.includes('自动生成的总结条目')) return true;
  return false;
}

/** 从条目名解析起始楼层，用于排序（解析失败返回 0） */
function parseStartFloor(entry: any): number {
  const m = typeof entry?.name === 'string' ? entry.name.match(/^总结_楼层(\d+)-\d+$/) : null;
  if (m) return parseInt(m[1], 10);
  // 兜底：从 comment 解析
  const c = typeof entry?.comment === 'string' ? entry.comment.match(/楼层范围:\s*(\d+)\s*-/) : null;
  if (c) return parseInt(c[1], 10);
  return 0;
}

/**
 * 重新平衡某个世界书里的总结条目：最近 keepRecent 条保持蓝灯，更早的改绿灯（带关键词）。
 *
 * @param TH TavernHelper
 * @param worldbookName 世界书名
 * @param keepRecent 最近保持常驻（蓝灯）的条数
 */
export async function rebalanceSummaryRecall(
  TH: any,
  worldbookName: string,
  keepRecent: number,
): Promise<void> {
  if (!TH || !worldbookName) return;
  if (typeof TH.updateWorldbookWith !== 'function') {
    console.warn('⚠️ TavernHelper.updateWorldbookWith 不可用，跳过智能唤醒平衡');
    return;
  }

  const keep = Math.max(0, Math.floor(keepRecent));
  const stop = getStopNames();

  await TH.updateWorldbookWith(worldbookName, (worldbook: any[]) => {
    // 找出所有插件总结条目并按起始楼层升序
    const summaryEntries = worldbook.filter(isPluginSummaryEntry);
    summaryEntries.sort((a, b) => parseStartFloor(a) - parseStartFloor(b));

    const total = summaryEntries.length;
    summaryEntries.forEach((entry, idx) => {
      const isRecent = idx >= total - keep; // 最后 keep 条是最近的
      if (isRecent) {
        // 蓝灯常驻
        entry.strategy = entry.strategy || {};
        entry.strategy.type = 'constant';
      } else {
        // 绿灯：需要关键词命中才注入
        const storedKeys: string[] = Array.isArray(entry.extra?.recall_keys)
          ? entry.extra.recall_keys.filter((k: any) => k && !stop.has(String(k).trim().toLowerCase()))
          : [];
        const keys = storedKeys.length ? storedKeys : extractRecallKeysFromContent(entry.content || '', stop);
        entry.strategy = entry.strategy || {};
        if (!keys.length) {
          // 防失忆兜底：一条关键词都提不出来的旧总结若转绿灯，将永远无法被激活（彻底失忆）。
          // 这种条目保持蓝灯常驻，宁可多花一点 token 也不丢记忆。
          entry.strategy.type = 'constant';
          console.warn(`⚠️ 「${entry.name}」提取不到唤醒关键词，保持蓝灯常驻以防失忆`);
        } else {
          entry.strategy.type = 'selective';
          entry.strategy.keys = keys;
          if (!entry.strategy.keys_secondary) {
            entry.strategy.keys_secondary = { logic: 'and_any', keys: [] };
          }
        }
      }
    });

    return worldbook;
  });

  console.log(`✅ 智能唤醒平衡完成：世界书「${worldbookName}」最近 ${keep} 条常驻，其余转绿灯唤醒`);
}

/** 判断条目是否是本插件创建的「大总结」条目 */
export function isPluginMegaSummaryEntry(entry: any): boolean {
  if (!entry) return false;
  if (entry.extra?.maomaomz_mega_summary) return true;
  if (typeof entry.name === 'string' && /^大总结_楼层\d+-\d+$/.test(entry.name)) return true;
  if (typeof entry.comment === 'string' && entry.comment.includes('自动生成的大总结条目')) return true;
  return false;
}

/** 从大总结条目名解析起始楼层，用于排序（解析失败返回 0） */
function parseMegaStartFloor(entry: any): number {
  const m = typeof entry?.name === 'string' ? entry.name.match(/^大总结_楼层(\d+)-\d+$/) : null;
  if (m) return parseInt(m[1], 10);
  const c = typeof entry?.comment === 'string' ? entry.comment.match(/大总结楼层范围:\s*(\d+)\s*-/) : null;
  if (c) return parseInt(c[1], 10);
  return 0;
}

/**
 * 重新平衡某个世界书里的「大总结」条目，兼顾省 token 与防失忆：
 *
 * - 最新 keepRecent 条大总结保持蓝灯常驻，作为"记忆主干"每轮注入——
 *   这是防失忆的兜底：即使某段旧剧情的绿灯小总结没被唤醒，AI 也始终有一份
 *   高度浓缩的全局背景，不会彻底断片。
 * - 更早的大总结转绿灯 + 关键词唤醒，平时休眠、提到相关旧角色/旧地点才注入，省 token。
 * - 提不出关键词的大总结保持蓝灯（宁可多花 token 也不失忆）。
 *
 * 大总结默认 keepRecent=1（一条主干足矣，大总结本身已是全局浓缩）。
 *
 * @param TH TavernHelper
 * @param worldbookName 世界书名
 * @param keepRecent 最新保持常驻（蓝灯）的大总结条数，默认 1
 */
export async function rebalanceMegaSummaryRecall(
  TH: any,
  worldbookName: string,
  keepRecent = 1,
): Promise<void> {
  if (!TH || !worldbookName) return;
  if (typeof TH.updateWorldbookWith !== 'function') {
    console.warn('⚠️ TavernHelper.updateWorldbookWith 不可用，跳过大总结唤醒平衡');
    return;
  }

  const keep = Math.max(1, Math.floor(keepRecent)); // 至少留 1 条主干蓝灯，防失忆
  const stop = getStopNames();

  await TH.updateWorldbookWith(worldbookName, (worldbook: any[]) => {
    const megaEntries = worldbook.filter(isPluginMegaSummaryEntry);
    if (!megaEntries.length) return worldbook;
    megaEntries.sort((a, b) => parseMegaStartFloor(a) - parseMegaStartFloor(b));

    const total = megaEntries.length;
    megaEntries.forEach((entry, idx) => {
      const isRecent = idx >= total - keep; // 最后 keep 条是最新的主干
      entry.strategy = entry.strategy || {};
      const backbone = entry.extra?.backbone_content;
      const full = entry.extra?.full_content;
      if (isRecent) {
        // 最新大总结：蓝灯常驻，作为记忆主干兜底。
        // content 用精简主干省 token（每轮注入的只是浓缩版）。
        entry.strategy.type = 'constant';
        // 先保住原始完整版（存量条目 content 就是完整版），再算精简主干
        const originalFull = full || entry.content || '';
        const bb = backbone || backboneFromFormattedText(originalFull);
        if (bb) {
          entry.content = bb;
          // 补存两份，方便后续在主干/唤醒之间切换内容（并保住完整版不丢）
          entry.extra = entry.extra || {};
          if (!entry.extra.full_content) entry.extra.full_content = originalFull;
          if (!entry.extra.backbone_content) entry.extra.backbone_content = bb;
        }
      } else {
        // 更早大总结：绿灯 + 关键词唤醒。
        // content 换回完整版——平时休眠零 token，一旦被提到就给出全部细节，记忆不丢。
        const storedKeys: string[] = Array.isArray(entry.extra?.recall_keys)
          ? entry.extra.recall_keys.filter((k: any) => k && !stop.has(String(k).trim().toLowerCase()))
          : [];
        const keys = storedKeys.length ? storedKeys : extractRecallKeysFromContent(full || entry.content || '', stop);
        if (!keys.length) {
          // 提不出关键词：保持蓝灯防失忆，但仍用精简主干省 token
          entry.strategy.type = 'constant';
          if (backbone) entry.content = backbone;
          console.warn(`⚠️ 大总结「${entry.name}」提取不到唤醒关键词，保持蓝灯常驻(精简)以防失忆`);
        } else {
          entry.strategy.type = 'selective';
          entry.strategy.keys = keys;
          if (!entry.strategy.keys_secondary) {
            entry.strategy.keys_secondary = { logic: 'and_any', keys: [] };
          }
          if (full) entry.content = full;
        }
      }
    });

    return worldbook;
  });

  console.log(`✅ 大总结唤醒平衡完成：世界书「${worldbookName}」最新 ${keep} 条主干常驻，其余转绿灯唤醒`);
}
