/**
 * 大总结（可复用逻辑）
 *
 * 把多条「小总结」合并成一条更完整的「大总结」，写入世界书并关闭被覆盖的小总结条目，节省 token。
 * 抽到这里是为了让「手动按钮（SummaryTab）」和「自动触发（index.ts 自动总结完成后）」共用同一套实现。
 */

import type { SummaryHistoryItem } from '../settings';
import { useSettingsStore, useSummaryHistoryStore } from '../settings';
import type { VisualSummary } from '../types/visual-summary';
import { summarizeVisualFromText, withSummaryRetry } from '../总结功能';
import { extractRecallKeys } from './smart-recall';
import { ensureSummaryWorldbook } from './summary-worldbook';
import { formatVisualSummaryBackbone, formatVisualSummaryForHistory } from './visual-summary-format';

/** 判断一条历史记录是否为「大总结」。 */
function isMegaItem(s: SummaryHistoryItem): boolean {
  return String(s?.content || '').includes('【大总结】');
}

/**
 * 找出「还没被任何大总结覆盖」的小总结。
 *
 * 大总结按楼层范围覆盖小总结，覆盖过的小总结不应再次并入新的大总结，
 * 否则每来一条新小总结就会把全部小总结重新合并、生成一条范围略大的大总结，
 * 导致世界书里堆出多条几乎重复、间隔很近的大总结。
 *
 * 判定：取所有大总结里最大的结束楼层 lastMegaEnd，只有「结束楼层 > lastMegaEnd」
 * 的小总结才算未覆盖、可参与下一次大总结。
 */
export function getUncoveredSmallSummaries(history: SummaryHistoryItem[]): SummaryHistoryItem[] {
  const megaEnds = history.filter(isMegaItem).map(s => s.end_id ?? -1);
  const lastMegaEnd = megaEnds.length ? Math.max(...megaEnds) : -1;
  return history.filter(s => !isMegaItem(s) && (s.end_id ?? s.start_id ?? 0) > lastMegaEnd);
}

/** 把大总结写入世界书，并（可选）关闭被它覆盖的小总结条目 */
async function bindMegaSummaryToWorldbook(
  visual: VisualSummary,
  startId: number,
  endId: number,
  closeSmalls: boolean,
): Promise<void> {
  const TH = (window as any).TavernHelper;
  if (!TH) return;

  const worldbookName = await ensureSummaryWorldbook();
  const fullContent = formatVisualSummaryForHistory(visual);
  const backboneContent = formatVisualSummaryBackbone(visual);
  const smartRecallOn = useSettingsStore().settings.smart_recall_enabled;
  // 开启智能唤醒时：大总结作为唯一「记忆主干」蓝灯常驻，content 用精简主干省 token；
  //   完整版存 extra.full_content 供查看/编辑。未开启时 content 用完整版常驻。
  const content = smartRecallOn ? backboneContent : fullContent;
  const entryName = `大总结_楼层${startId}-${endId}`;

  const isPluginMega = (entry: any): boolean =>
    entry?.extra?.maomaomz_mega_summary === true ||
    (typeof entry?.name === 'string' && /^大总结_楼层\d+-\d+$/.test(entry.name)) ||
    (typeof entry?.comment === 'string' && entry.comment.includes('自动生成的大总结条目'));

  // 判断一个小总结世界书条目是否被本次大总结覆盖（结束楼层 <= 新大总结的 endId）。
  // 直接按楼层范围判断，而不是只认传进来的 coveredSmalls，这样能一并清掉历史遗留的、
  // 散落在覆盖范围内的旧小总结条目（修复之前"大总结没写进去、小总结全留着"的烂状态）。
  const isCoveredSmall = (entry: any): boolean => {
    if (typeof entry?.name !== 'string') return false;
    const m = entry.name.match(/^总结_楼层(\d+)-(\d+)$/);
    if (!m) return false;
    const smallEnd = parseInt(m[2], 10);
    return Number.isFinite(smallEnd) && smallEnd <= endId;
  };

  const newEntry = {
    name: entryName,
    enabled: true,
    strategy: {
      type: 'constant' as const,
      keys: [],
      keys_secondary: { logic: 'and_any' as const, keys: [] },
      scan_depth: 'same_as_global' as const,
    },
    position: {
      type: 'before_character_definition' as const,
      role: 'system' as const,
      depth: 1,
    },
    content,
    comment: `自动生成的大总结条目 - 大总结楼层范围: ${startId} - ${endId}`,
    insertion_order: 0,
    recursion: { prevent_incoming: true, prevent_outgoing: true, delay_until: null },
    extra: {
      maomaomz_mega_summary: true,
      recall_keys: extractRecallKeys(visual),
      full_content: fullContent,
      backbone_content: backboneContent,
    },
    uid: Date.now(),
  };

  // 一次性原子更新世界书：删掉「所有旧大总结条目」+「被本次覆盖的小总结条目」，再写入这一条新大总结。
  // 这样世界书里永远只有一条大总结（吸收式合并），被覆盖的小总结直接删除而非禁用，token 天然下降。
  try {
    await TH.updateWorldbookWith(
      worldbookName,
      (worldbook: any[]) => {
        const kept = worldbook.filter(entry => {
          if (isPluginMega(entry)) return false; // 删掉所有旧大总结
          if (closeSmalls && isCoveredSmall(entry)) return false; // 删掉被覆盖（结束楼层<=endId）的小总结
          return true;
        });
        kept.push(newEntry);
        return kept;
      },
      { render: 'immediate' },
    );
    console.log(
      `✅ 大总结已写入世界书「${worldbookName}」（覆盖楼层 ${startId}-${endId}），` +
        `已清理旧大总结与被覆盖小总结条目，世界书内大总结恒为 1 条`,
    );
  } catch (e) {
    console.error('❌ 写入大总结世界书失败:', e);
    // 兜底：至少把大总结条目补进去，避免出现「历史有、世界书没有」的不一致
    try {
      await TH.createWorldbookEntries?.(worldbookName, [newEntry], { render: 'immediate' });
    } catch (e2) {
      console.error('❌ 兜底创建大总结条目也失败:', e2);
    }
  }
}

export interface MegaSummaryResult {
  visual: VisualSummary;
  startId: number;
  endId: number;
  mergedCount: number;
}

/**
 * 执行一次大总结：合并当前聊天历史里的小总结、写入历史与世界书。
 *
 * @param history 当前聊天的总结历史（按时间排序，新在前或在后都可，内部按楼层取范围）
 * @returns 大总结结果；若不满足条件（小总结不足 2 条）返回 null
 */
export async function runMegaSummary(
  history: SummaryHistoryItem[],
  opts?: { force?: boolean },
): Promise<MegaSummaryResult | null> {
  // 吸收式合并：把「已有的那条大总结（如果有）」和「所有还没被它覆盖的小总结」合成一条新的大总结，
  // 覆盖从最早到最新的整段。世界书里因此永远只有一条大总结，不再并排堆多条。
  const uncoveredSmalls = getUncoveredSmallSummaries(history);
  const existingMegas = history.filter(isMegaItem);

  // 触发条件：
  // - 正常（自动/手动生成大总结）：未覆盖小总结 >= 2 才合并。
  // - force（一键整理记忆）：只要有「可收拢的冗余」就重建——多条大总结、或大总结+散落小总结、
  //   或 >=2 条未覆盖小总结，都会被合并成一条并重写世界书，用于修复历史遗留的混乱状态。
  const mergeableCount = existingMegas.length + uncoveredSmalls.length;
  const shouldRun = opts?.force
    ? existingMegas.length >= 2 || mergeableCount >= 2
    : uncoveredSmalls.length >= 2;
  if (!shouldRun) return null;

  // 合并输入 = 已有大总结（按楼层在前）+ 未覆盖小总结（按楼层排序）
  const orderedMegas = existingMegas.slice().sort((a, b) => (a.start_id ?? 0) - (b.start_id ?? 0));
  const orderedSmalls = uncoveredSmalls.slice().sort((a, b) => (a.start_id ?? 0) - (b.start_id ?? 0));

  const parts: string[] = [];
  orderedMegas.forEach(m => {
    parts.push(`【已有大总结 (楼层${m.start_id}-${m.end_id})】\n${m.content}`);
  });
  orderedSmalls.forEach((item, idx) => {
    parts.push(`【第${idx + 1}段新总结 (楼层${item.start_id}-${item.end_id})】\n${item.content}`);
  });
  const allSummaries = parts.join('\n\n');

  // 新大总结覆盖范围：从所有输入里的最小起点到最大终点（含已有大总结）
  const allItems = [...orderedMegas, ...orderedSmalls];
  const startId = Math.min(...allItems.map(s => s.start_id ?? 0));
  const endId = Math.max(...allItems.map(s => s.end_id ?? 0));

  // 带上「仍未了结的伏笔 / 待跟进」，让大总结据后续剧情核对更新，剪掉过期条目
  let prior: { foreshadowing: string[]; todo: string[] } | undefined;
  try {
    prior = useSummaryHistoryStore().collectPriorOpenContext(startId);
  } catch (e) {
    console.warn('收集过往伏笔/待跟进失败（忽略）:', e);
  }

  const visual = await withSummaryRetry(() => summarizeVisualFromText(allSummaries, startId, endId, prior));
  const megaContent = `【大总结】\n${formatVisualSummaryForHistory(visual)}`;

  // 历史记录：删掉被合并进去的旧大总结记录 + 被覆盖的小总结记录（结束楼层 <= endId），
  // 再写入新的合并大总结。这样面板历史与世界书口径一致，不再显示已被吸收的旧小总结、token 概览也不虚高。
  try {
    const store = useSummaryHistoryStore();
    for (const m of existingMegas) {
      try {
        store.removeSummaryByRange(m.start_id, m.end_id);
      } catch {
        /* ignore */
      }
    }
    store.removeCoveredSmallSummaries(endId);
    store.addSummary(startId, endId, megaContent, visual);
  } catch (e) {
    console.warn('写入大总结历史失败（忽略）:', e);
  }

  // 写世界书：删掉所有旧大总结条目 + 被覆盖的小总结条目，只留这一条新大总结
  const closeSmalls = useSettingsStore().settings.mega_summary_close_smalls !== false;
  await bindMegaSummaryToWorldbook(visual, startId, endId, closeSmalls);

  return { visual, startId, endId, mergedCount: orderedSmalls.length };
}
