import { globalPinia } from './globalPinia';
import { useSettingsStore } from './settings';

type ToastrMethod = 'success' | 'info' | 'warning' | 'error';

const SILENCED_METHODS = new Set<ToastrMethod>(['success', 'info']);
const VERSION_CHECK_TOAST_CLASS = 'maomaomz-version-check';
let installed = false;
const originalMethods = new Map<ToastrMethod, Function>();

function isSilentNotificationsEnabled(): boolean {
  try {
    return useSettingsStore(globalPinia).settings.silent_notifications !== false;
  } catch {
    return true;
  }
}

export function getSharedToastr(): any {
  try {
    if (window.parent && window.parent !== window && (window.parent as any).toastr) {
      return (window.parent as any).toastr;
    }
  } catch {
    // ignore cross-origin access errors
  }
  return (window as any).toastr;
}

function getStyleDocuments(): Document[] {
  const docs = [document];
  try {
    if (window.parent?.document && window.parent.document !== document) {
      docs.push(window.parent.document);
    }
  } catch {
    // ignore cross-origin access errors
  }
  return docs;
}

function ensureToastrAbovePanel() {
  try {
    const styleId = 'maomaomz-toastr-layer-fix';
    for (const doc of getStyleDocuments()) {
      if (doc.getElementById(styleId)) continue;
      const style = doc.createElement('style');
      style.id = styleId;
      style.textContent = `
        /* 仅提升 toastr 容器层级，避免被插件面板遮挡（不改外观、不改位置） */
        #toast-container,
        .toast-container,
        .toast {
          z-index: 2147483647 !important;
        }

        /* ===== iOS 风格通知（统一深色毛玻璃胶囊）=====
         * 严格限定到插件自己的通知 .maomaomz-toast，
         * 绝不影响酒馆 (SillyTavern) 自身的通知样式与位置。 */
        #toast-container > .maomaomz-toast {
          position: relative !important;
          font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'PingFang SC', 'Microsoft YaHei', sans-serif !important;
          padding: 14px 38px 14px 34px !important;
          border-radius: 18px !important;
          box-shadow: 0 10px 34px rgba(0, 0, 0, 0.36) !important;
          background-image: none !important;
          background-color: rgba(30, 30, 32, 0.74) !important;
          color: #ffffff !important;
          border: 0.5px solid rgba(255, 255, 255, 0.14) !important;
          backdrop-filter: saturate(180%) blur(24px) !important;
          -webkit-backdrop-filter: saturate(180%) blur(24px) !important;
          font-size: 14px !important;
          line-height: 1.5 !important;
          width: auto !important;
          min-width: 220px !important;
          max-width: 360px !important;
          background-position: initial !important;
          background-repeat: no-repeat !important;
          display: block !important;
        }
        /* 各类型自带的对勾/感叹号等背景图标优先级更高，逐个强制清除 */
        #toast-container > .maomaomz-toast.toast-success,
        #toast-container > .maomaomz-toast.toast-error,
        #toast-container > .maomaomz-toast.toast-info,
        #toast-container > .maomaomz-toast.toast-warning {
          background-image: none !important;
        }
        #toast-container > .maomaomz-toast .toast-title {
          font-weight: 600 !important;
          font-size: 14px !important;
          margin: 0 0 3px 0 !important;
          line-height: 1.4 !important;
        }
        #toast-container > .maomaomz-toast .toast-message {
          font-size: 13px !important;
          color: rgba(235, 235, 245, 0.92) !important;
          word-break: break-word !important;
          white-space: pre-line !important;
          margin: 0 !important;
        }
        /* 左侧统一小圆点，按类型变色（iOS 系统色），绝对定位不占文字行 */
        #toast-container > .maomaomz-toast::before {
          content: '' !important;
          width: 8px !important;
          height: 8px !important;
          border-radius: 50% !important;
          background: #0a84ff !important;
          position: absolute !important;
          left: 15px !important;
          top: 18px !important;
          margin: 0 !important;
          display: block !important;
        }
        #toast-container > .maomaomz-toast.toast-success::before { background: #30d158 !important; }
        #toast-container > .maomaomz-toast.toast-error::before { background: #ff453a !important; }
        #toast-container > .maomaomz-toast.toast-warning::before { background: #ff9f0a !important; }
        #toast-container > .maomaomz-toast.toast-info::before { background: #0a84ff !important; }
        /* 进度条：细、白、半透明 */
        #toast-container > .maomaomz-toast .toast-progress {
          background-color: rgba(255, 255, 255, 0.45) !important;
          opacity: 0.7 !important;
          height: 2px !important;
          border-radius: 2px !important;
        }
        /* 关闭按钮：绝对定位到右上角，不挤压文字 */
        #toast-container > .maomaomz-toast .toast-close-button {
          position: absolute !important;
          top: 8px !important;
          right: 12px !important;
          color: rgba(255, 255, 255, 0.5) !important;
          text-shadow: none !important;
          opacity: 1 !important;
          font-weight: 400 !important;
          font-size: 15px !important;
        }
      `;
      doc.head.appendChild(style);
    }
  } catch (error) {
    console.warn('安装提示层级修复失败:', error);
  }
}

// ===== 通知自动消失看门狗 =====
// 不论是哪一个 toastr 实例、用了什么 options 创建的通知，
// 都通过 MutationObserver 兜底：超过指定时间强制淡出移除，杜绝“卡住不消失”。
const WATCHDOG_TIMEOUT = 4000; // ms
const watchdogTimers = new WeakMap<Element, number>();
const installedWatchdogDocs = new WeakSet<Document>();

function scheduleToastRemoval(node: Element) {
  if (watchdogTimers.has(node)) return;
  // 错误类通知给更长的停留时间（可能含需要阅读的报错），其余统一短时移除。
  // 不再放过任何通知——版本检查/更新提示等也必须自动消失。
  const isError = node.classList.contains('toast-error');
  const timeout = isError ? 10000 : WATCHDOG_TIMEOUT;
  const timer = window.setTimeout(() => {
    try {
      const el = node as HTMLElement;
      el.style.transition = 'opacity 0.35s ease';
      el.style.opacity = '0';
      window.setTimeout(() => {
        try {
          node.remove();
        } catch {
          /* ignore */
        }
      }, 380);
    } catch {
      try {
        node.remove();
      } catch {
        /* ignore */
      }
    }
  }, timeout);
  watchdogTimers.set(node, timer);
}

function installToastWatchdog() {
  for (const doc of getStyleDocuments()) {
    if (installedWatchdogDocs.has(doc)) continue;
    try {
      const observer = new MutationObserver(mutations => {
        for (const m of mutations) {
          m.addedNodes.forEach(n => {
            if (!(n instanceof Element)) return;
            // toastr 通知节点：#toast-container > div.toast-*
            if (n.parentElement?.id === 'toast-container' || n.id === 'toast-container') {
              if (n.id === 'toast-container') {
                n.querySelectorAll(':scope > div').forEach(scheduleToastRemoval);
              } else {
                scheduleToastRemoval(n);
              }
            }
          });
        }
      });
      observer.observe(doc.body || doc.documentElement, { childList: true, subtree: true });
      installedWatchdogDocs.add(doc);
      // 兜底：处理观察器安装前已经存在的通知
      doc.querySelectorAll('#toast-container > div').forEach(scheduleToastRemoval);
    } catch (error) {
      console.warn('安装通知看门狗失败:', error);
    }
  }
}

export function clearVersionCheckToasts() {
  const toastr = getSharedToastr();
  if (!toastr?.clear) return;

  for (const doc of getStyleDocuments()) {
    doc.querySelectorAll(`#toast-container .${VERSION_CHECK_TOAST_CLASS}`).forEach(node => {
      try {
        toastr.clear($(node));
      } catch {
        node.remove();
      }
    });
  }
}

export function installNotificationControls() {
  if (installed || typeof window === 'undefined') return;
  ensureToastrAbovePanel();
  installToastWatchdog();

  const currentToastr = getSharedToastr();
  if (!currentToastr || typeof currentToastr !== 'object') return;
  installed = true;

  // 强制设置合理的默认项，确保通知会自动消失（避免某些环境下 timeOut=0 卡住）
  try {
    currentToastr.options = {
      ...(currentToastr.options || {}),
      timeOut: 3000,
      extendedTimeOut: 1500,
      closeButton: true,
      tapToDismiss: true,
      newestOnTop: true,
      preventDuplicates: true,
    };
  } catch {
    /* ignore */
  }

  for (const method of ['success', 'info', 'warning', 'error'] as ToastrMethod[]) {
    const originalMethod = currentToastr[method];
    if (typeof originalMethod !== 'function') continue;
    if (!originalMethods.has(method)) {
      originalMethods.set(method, originalMethod);
    }
    currentToastr[method] = (...args: any[]) => {
      ensureToastrAbovePanel();
      if (isSilentNotificationsEnabled() && SILENCED_METHODS.has(method)) {
        console.log(`[静默提示] ${method}:`, args[0] || '');
        return null;
      }
      return originalMethods.get(method)?.apply(currentToastr, args);
    };
  }
}

const PLUGIN_TOAST_CLASS = 'maomaomz-toast';

/** 合并出带插件专属 class 的 options，确保只有插件通知套用 iOS 样式 */
function withPluginToastClass(options?: any) {
  const merged = { ...(options || {}) };
  const existing = typeof merged.toastClass === 'string' ? merged.toastClass : '';
  merged.toastClass = existing.includes(PLUGIN_TOAST_CLASS)
    ? existing
    : `${PLUGIN_TOAST_CLASS}${existing ? ' ' + existing : ''}`;
  return merged;
}

export function notify(method: ToastrMethod, message: string, title?: string, options?: any) {
  ensureToastrAbovePanel();
  const toastr = getSharedToastr();
  if (!toastr || typeof toastr[method] !== 'function') {
    console[method === 'error' ? 'error' : method === 'warning' ? 'warn' : 'log'](message);
    return;
  }
  return toastr[method](message, title, withPluginToastClass(options));
}

export function notifyUser(method: ToastrMethod, message: string, title?: string, options?: any) {
  ensureToastrAbovePanel();
  const toastr = getSharedToastr();
  const original = originalMethods.get(method) ?? toastr?.[method];
  if (typeof original !== 'function') {
    console[method === 'error' ? 'error' : method === 'warning' ? 'warn' : 'log'](message);
    return;
  }
  return original.call(toastr, message, title, withPluginToastClass(options));
}

export function notifyVersionCheckResult(method: ToastrMethod, message: string, title?: string, options?: any) {
  clearVersionCheckToasts();
  return notifyUser(method, message, title, {
    toastClass: `${VERSION_CHECK_TOAST_CLASS} toast-${method}`,
    preventDuplicates: true,
    timeOut: method === 'error' ? 8000 : 5000,
    ...options,
  });
}
