/**
 * 通用工具函数
 */

/**
 * 复制文本到剪贴板（支持 iframe 环境）
 * @param text 要复制的文本
 * @param successMessage 成功提示消息
 * @returns Promise<boolean> 复制是否成功
 */
export async function copyToClipboard(text: string, successMessage?: string): Promise<boolean> {
  try {
    // 策略1: 尝试在父窗口中使用 execCommand（最稳定）
    if (window.parent && window.parent.document) {
      try {
        const textarea = window.parent.document.createElement('textarea');
        textarea.value = text;
        textarea.style.position = 'fixed';
        textarea.style.opacity = '0';
        window.parent.document.body.appendChild(textarea);
        textarea.select();
        const success = window.parent.document.execCommand('copy');
        window.parent.document.body.removeChild(textarea);

        if (success) {
          if (successMessage) {
            toastr.success(successMessage);
          }
          return true;
        }
      } catch (e) {
        console.warn('父窗口复制失败，尝试其他方法', e);
      }
    }

    // 策略2: 尝试在当前窗口使用 execCommand
    try {
      const textarea = document.createElement('textarea');
      textarea.value = text;
      textarea.style.position = 'fixed';
      textarea.style.opacity = '0';
      document.body.appendChild(textarea);
      textarea.select();
      const success = document.execCommand('copy');
      document.body.removeChild(textarea);

      if (success) {
        if (successMessage) {
          toastr.success(successMessage);
        }
        return true;
      }
    } catch (e) {
      console.warn('当前窗口复制失败，尝试 Clipboard API', e);
    }

    // 策略3: 使用现代 Clipboard API
    if (navigator.clipboard && navigator.clipboard.writeText) {
      await navigator.clipboard.writeText(text);
      if (successMessage) {
        toastr.success(successMessage);
      }
      return true;
    }

    throw new Error('所有复制方法都失败了');
  } catch (error) {
    console.error('复制失败:', error);
    toastr.error('复制失败，请手动复制');
    return false;
  }
}

/**
 * 安全获取脚本 ID
 * 插件环境使用固定ID
 */
export function getScriptIdSafe(): string {
  // 插件环境直接返回固定ID
  if (!globalScriptId) {
    globalScriptId = 'maomaomz_extension_v1';
  }
  return globalScriptId;
}

/**
 * 安全获取聊天 ID（插件环境）
 */
export function getChatIdSafe(): string {
  try {
    // 插件环境：尝试多种方式获取聊天ID
    // 1. 优先使用 SillyTavern.getContext()
    if (typeof SillyTavern !== 'undefined' && typeof SillyTavern.getContext === 'function') {
      const context = SillyTavern.getContext();
      if (context?.chatId) {
        return context.chatId;
      }
    }

    // 2. 尝试 TavernHelper.getChatId()
    if (
      typeof (window as any).TavernHelper !== 'undefined' &&
      typeof (window as any).TavernHelper.getChatId === 'function'
    ) {
      const chatId = (window as any).TavernHelper.getChatId();
      if (chatId) return chatId;
    }

    // 3. 尝试 SillyTavern.getCurrentChatId() 方法
    if (typeof SillyTavern !== 'undefined' && typeof SillyTavern.getCurrentChatId === 'function') {
      const chatId = SillyTavern.getCurrentChatId();
      if (chatId) return chatId;
    }

    // 4. 降级：尝试 SillyTavern.chatId 属性
    if (typeof SillyTavern !== 'undefined' && SillyTavern.chatId) {
      return SillyTavern.chatId;
    }

    console.warn('⚠️ 无法获取聊天ID，可能未打开任何聊天');
    return '';
  } catch (error) {
    console.error('获取聊天 ID 失败:', error);
    return '';
  }
}

// 全局脚本 ID（用于在 iframe 加载完成前缓存）
export interface ChatSnapshot {
  lastMessageId: number;
  messages: any[];
  source:
    | 'tavernhelper_last_id'
    | 'tavernhelper_messages'
    | 'sillytavern_chat'
    | 'window_getLastMessageId'
    | 'window_getChatMessages'
    | 'none';
}

const EMPTY_CHAT_SNAPSHOT: ChatSnapshot = {
  lastMessageId: -1,
  messages: [],
  source: 'none',
};

function normalizeMessages(messages: unknown): any[] {
  return Array.isArray(messages) ? messages : [];
}

/**
 * Safely read current chat state from multiple runtime APIs.
 * This keeps fallback order in one place and avoids repeated branches.
 */
export function getChatSnapshotSafe(): ChatSnapshot {
  const w = window as any;

  try {
    const tavernHelper = w.TavernHelper;

    if (tavernHelper && typeof tavernHelper.getLastMessageId === 'function') {
      try {
        const lastMessageId = Number(tavernHelper.getLastMessageId());
        if (Number.isFinite(lastMessageId) && lastMessageId >= 0) {
          const messages =
            typeof tavernHelper.getChatMessages === 'function'
              ? normalizeMessages(tavernHelper.getChatMessages('0-{{lastMessageId}}'))
              : [];
          return { lastMessageId, messages, source: 'tavernhelper_last_id' };
        }
      } catch (error) {
        console.warn('getLastMessageId from TavernHelper failed:', error);
      }
    }

    if (tavernHelper && typeof tavernHelper.getChatMessages === 'function') {
      try {
        const messages = normalizeMessages(tavernHelper.getChatMessages('0-{{lastMessageId}}'));
        if (messages.length > 0) {
          return {
            lastMessageId: messages.length - 1,
            messages,
            source: 'tavernhelper_messages',
          };
        }
      } catch (error) {
        console.warn('getChatMessages from TavernHelper failed:', error);
      }
    }

    if (typeof SillyTavern !== 'undefined' && Array.isArray(SillyTavern.chat)) {
      const messages = SillyTavern.chat;
      return {
        lastMessageId: messages.length - 1,
        messages,
        source: 'sillytavern_chat',
      };
    }

    if (typeof w.getLastMessageId === 'function') {
      try {
        const lastMessageId = Number(w.getLastMessageId());
        if (Number.isFinite(lastMessageId) && lastMessageId >= 0) {
          const messages =
            typeof w.getChatMessages === 'function' ? normalizeMessages(w.getChatMessages('0-{{lastMessageId}}')) : [];
          return { lastMessageId, messages, source: 'window_getLastMessageId' };
        }
      } catch (error) {
        console.warn('getLastMessageId from window failed:', error);
      }
    }

    if (typeof w.getChatMessages === 'function') {
      try {
        const messages = normalizeMessages(w.getChatMessages('0-{{lastMessageId}}'));
        if (messages.length > 0) {
          return {
            lastMessageId: messages.length - 1,
            messages,
            source: 'window_getChatMessages',
          };
        }
      } catch (error) {
        console.warn('getChatMessages from window failed:', error);
      }
    }
  } catch (error) {
    console.warn('getChatSnapshotSafe failed:', error);
  }

  return EMPTY_CHAT_SNAPSHOT;
}

export function getLastMessageIdSafe(defaultValue: number = -1): number {
  const { lastMessageId } = getChatSnapshotSafe();
  return lastMessageId >= 0 ? lastMessageId : defaultValue;
}

export function getChatMessagesSafe(): any[] {
  return getChatSnapshotSafe().messages;
}
let globalScriptId: string | null = null;

/**
 * 设置全局脚本 ID
 */
export function setGlobalScriptId(id: string): void {
  globalScriptId = id;
}

/**
 * 获取全局脚本 ID
 */
export function getGlobalScriptId(): string | null {
  return globalScriptId;
}

/**
 * 统一处理 API 错误响应
 * @param response Fetch Response 对象
 * @returns Promise<never> 抛出格式化的错误
 */
export async function handleApiError(response: Response): Promise<never> {
  let errorMessage = `API 错误: ${response.status}`;

  // 根据状态码提供友好的错误提示
  if (response.status === 503) {
    errorMessage = 'AI 服务暂时不可用 (503)，请稍后重试';
  } else if (response.status === 429) {
    errorMessage = 'API 请求频率过高 (429)，请稍后重试';
  } else if (response.status === 401) {
    errorMessage = 'API 密钥无效 (401)，请检查设置';
  } else if (response.status === 403) {
    errorMessage = 'API 访问被拒绝 (403)，请检查权限';
  } else if (response.status === 400) {
    errorMessage = 'API 请求参数错误 (400)';
  } else if (response.status === 500) {
    errorMessage = 'AI 服务器内部错误 (500)';
  }

  // 尝试获取详细错误信息
  try {
    const errorData = await response.json();
    if (errorData.error?.message) {
      errorMessage += `: ${errorData.error.message}`;
    } else if (errorData.message) {
      errorMessage += `: ${errorData.message}`;
    }
  } catch {
    // 如果不是 JSON，尝试获取文本
    try {
      const errorText = await response.text();
      if (errorText && errorText.length < 500) {
        errorMessage += `: ${errorText}`;
      }
    } catch {
      // 忽略错误
    }
  }

  throw new Error(errorMessage);
}

