export interface VisualSummaryCharacter {
  name: string;
  status: string;
  attitude: string;
  memory: string;
}

export interface VisualSummaryRelationChange {
  from: string;
  to: string;
  change: string;
  reason: string;
}

export interface VisualSummaryWorldbookCandidate {
  type: 'character' | 'location' | 'plot' | 'setting' | 'item' | 'other';
  title: string;
  content: string;
  enabled: boolean;
}

export interface VisualSummary {
  title: string;
  range: {
    start: number;
    end: number;
  };
  time: string;
  location: string;
  overview: string;
  events: string[];
  characters: VisualSummaryCharacter[];
  relationshipChanges: VisualSummaryRelationChange[];
  foreshadowing: string[];
  todo: string[];
  worldbookCandidates: VisualSummaryWorldbookCandidate[];
}

export function createEmptyVisualSummary(start: number, end: number): VisualSummary {
  return {
    title: `可视化总结 ${start}-${end}`,
    range: { start, end },
    time: '',
    location: '',
    overview: '',
    events: [],
    characters: [],
    relationshipChanges: [],
    foreshadowing: [],
    todo: [],
    worldbookCandidates: [],
  };
}
