import { createPinia, setActivePinia, type Pinia } from 'pinia';

/**
 * 🔥 跨模块单例 Pinia。
 *
 * 关键背景：发布时入口被打了缓存戳，酒馆加载的是 `dist/index.js?v=xxxx`，
 * 而懒加载的分包（浮动面板等）里 `import './index.js'` 没有这个 `?v=`，
 * 浏览器把这两个 URL 当成**两个不同的模块**，于是整个入口被执行了两次，
 * 产生两份 `globalPinia` 和两份 settings store —— 面板里改的设置被另一份 store
 * 的旧值回写覆盖，刷新后就"丢了"。
 *
 * 解决办法：把 Pinia 实例挂到 window 上做成真正的全局单例。无论入口被加载几次、
 * 在几个模块图里，都复用同一个 Pinia；Pinia 会按 store id 去重，最终全程只有
 * 一个 'settings' store，彻底消除互相覆盖。
 */
const PINIA_KEY = '__MAOMAOMZ_GLOBAL_PINIA__';

export const globalPinia: Pinia = (window as any)[PINIA_KEY] ?? createPinia();
(window as any)[PINIA_KEY] = globalPinia;

// 设为活动实例，确保在非组件代码（index.ts 等）里直接 useXxxStore() 也命中同一实例
setActivePinia(globalPinia);
