import { useSettingsStore, useSummaryHistoryStore } from './settings';
import { useTaskStore } from './taskStore';
import { callAIWithTavernSupport } from './utils/api';

type PolishMode = 'natural' | 'expand';

let previousDraft = '';
let activeRequest = false;
let observer: MutationObserver | null = null;

function getInput(): HTMLTextAreaElement | null {
  return document.querySelector<HTMLTextAreaElement>('#send_textarea, textarea[name="send_textarea"]');
}

function setDraft(input: HTMLTextAreaElement, value: string) {
  input.value = value;
  input.dispatchEvent(new Event('input', { bubbles: true }));
  input.dispatchEvent(new Event('change', { bubbles: true }));
  input.focus();
  input.setSelectionRange(value.length, value.length);
}

function trimContext(text: string, limit: number) {
  return text.length > limit ? `${text.slice(0, limit)}\n[内容已截断]` : text;
}

function buildFormatPreference(settings: any) {
  const formatPrompt = settings.input_polish_format_prompt?.trim();
  if (formatPrompt) return `【格式要求】\n${formatPrompt}`;
  const dialogueQuotes = settings.input_polish_dialogue_quotes?.trim() || '「」';
  const nestedQuotes = settings.input_polish_nested_quotes?.trim() || '『』';
  const actionBrackets = settings.input_polish_action_brackets?.trim() || '【】';
  const actionDefinition = settings.input_polish_action_definition?.trim() || '动作、神态、心理或舞台指示';
  return `【用户格式偏好】\n对话使用：${dialogueQuotes}\n引用他人原话或嵌套引号使用：${nestedQuotes}\n${actionBrackets} 表示：${actionDefinition}\n润色时严格沿用这套符号；如果原文已经使用这些格式，不得改成其他引号或括号。`;
}

function getPolishContext() {
  const st = (window as any).SillyTavern;
  let stContext = st;
  try {
    stContext = typeof st?.getContext === 'function' ? st.getContext() : st;
  } catch (error) {
    console.warn('读取酒馆上下文失败（忽略）:', error);
  }
  const userName = String(stContext?.name1 || st?.name1 || '用户');
  const charName = String(stContext?.name2 || st?.name2 || '角色');
  let visibleMessages: string[] = [];

  try {
    // 直接读取酒馆当前已加载的聊天数组，避免 TavernHelper 全量读取在部分版本卡住。
    const messages = Array.isArray(stContext?.chat) ? stContext.chat : Array.isArray(st?.chat) ? st.chat : [];
    if (Array.isArray(messages)) {
      visibleMessages = messages
        .filter(message => !message?.is_hidden && !message?.hidden && !message?.isHidden)
        .slice(-16)
        .map(message => {
          const messageRole = String(message?.role || '').toLowerCase();
          const messageName = String(message?.name || '');
          const isUser = message?.is_user === true || messageRole === 'user' || messageRole === 'human' || messageName === userName;
          const role = isUser ? `用户（${userName}）` : `角色（${messageName || charName}）`;
          const content = String(message?.message || message?.mes || message?.content || '').trim();
          return content ? `${role}：${content}` : '';
        })
        .filter(Boolean);
    }
  } catch (error) {
    console.warn('读取可见聊天上下文失败（忽略）:', error);
  }

  const summaries = useSummaryHistoryStore()
    .getSummaryHistory()
    .slice(0, 4)
    .map(item => `楼层 ${item.start_id}-${item.end_id}：${String(item.content || '').trim()}`)
    .filter(Boolean)
    .join('\n\n');

  return {
    visible: trimContext(visibleMessages.join('\n\n'), 12000),
    summaries: trimContext(summaries, 6000),
    visibleCount: visibleMessages.length,
    userName,
    charName,
  };
}

function closeMenu() {
  document.querySelector('#maomaomz-input-polisher-menu')?.remove();
}

function showMenu(anchor: HTMLElement) {
  closeMenu();
  const menu = document.createElement('div');
  menu.id = 'maomaomz-input-polisher-menu';
  menu.innerHTML = `
    <button type="button" data-mode="natural">自然润色</button>
    <button type="button" data-mode="expand">扩写细节</button>
  `;
  document.body.appendChild(menu);

  const rect = anchor.getBoundingClientRect();
  menu.style.left = `${Math.max(8, rect.left)}px`;
  menu.style.top = `${Math.max(8, rect.top - menu.offsetHeight - 8)}px`;
  menu.querySelectorAll<HTMLButtonElement>('button[data-mode]').forEach(button => {
    button.addEventListener('click', () => void polishInput(button.dataset.mode as PolishMode));
  });
}

async function polishInput(mode: PolishMode) {
  closeMenu();
  const input = getInput();
  const source = input?.value.trim();
  if (!input || !source || activeRequest) {
    if (!source) window.toastr?.warning('请先在输入框写下需要润色的内容');
    return;
  }

  const settings = useSettingsStore().settings;
  if (!settings.api_endpoint || (!settings.api_key && !settings.use_tavern_api)) {
    window.toastr?.warning('请先在猫猫工具的 AI 设置中配置可用的模型');
    return;
  }

  activeRequest = true;
  updateControls();
  window.toastr?.info(mode === 'natural' ? '正在润色输入内容…' : '正在扩写输入内容…');
  const taskStore = useTaskStore();
  const taskId = taskStore.createTask('input_polish', mode === 'natural' ? '润色酒馆输入' : '扩写酒馆输入');
  taskStore.updateTaskProgress(taskId, 15, '正在读取当前草稿…');
  const context = getPolishContext();
  taskStore.updateTaskProgress(taskId, 28, '已读取可见上下文与总结，正在组织润色要求…');
  const identityGuard = `待润色文本由用户「${context.userName}」说出，角色是「${context.charName}」。绝不能把用户称呼角色的词改成用户自称，绝不能把用户的动作或心理改写成角色的动作或心理。只输出用户文本的润色结果。`;
  const formatPreference = buildFormatPreference(settings);

  const systemPrompt =
    mode === 'natural'
      ? '你是中文角色扮演文本编辑。只润色用户提供的文本，不得替用户续写、补写后续剧情或新增原文没有表达的意图。给出的聊天上下文和剧情总结只用于核对称呼、关系、语气、时态和既有事实，使润色结果贴合当前剧情。请明显但克制地优化原文：重组生硬或重复的句式，换成更准确、生动、自然的措辞，并补足原文已有内容之间必要的衔接。必须保留原意、人称、时态、角色名、对白、格式和所有事实。若输入过短或没有可润色的实质内容（例如“继续”），请原样保留或只调整标点，绝不能据上下文生成新内容。不要添加解释、标题、引号或任何前后缀。只输出润色后的正文。'
      : '你是中文角色扮演文本编辑。只扩写用户提供的文本中已经存在的动作、情绪、感官或描写，不得替用户续写、补写后续剧情或新增原文没有表达的意图。给出的聊天上下文和剧情总结只用于核对称呼、关系、语气、时态和既有事实，使润色结果贴合当前剧情。可基于原文已有内容适度补足动作、神态、感官和环境细节，让画面更有代入感；不得推进剧情，不得替其他角色决定行动。必须保留原意、人称、时态、角色名、对白、格式和所有事实。若输入过短或没有可扩写的实质内容（例如“继续”），请原样保留或只调整标点，绝不能据上下文生成新内容。不要添加解释、标题、引号或任何前后缀。只输出润色后的正文。';

  try {
    taskStore.updateTaskProgress(taskId, 35, '正在调用 AI 处理文本…');
    const result = await callAIWithTavernSupport(
      [
        { role: 'system', content: systemPrompt },
        { role: 'system', content: identityGuard },
        { role: 'system', content: formatPreference },
        {
          role: 'system',
          content: `【身份定义】\n用户是「${context.userName}」，角色是「${context.charName}」。\n\n【当前可见聊天上下文】\n${context.visible || '（当前没有可读取的可见聊天消息）'}\n\n【已有剧情总结】\n${context.summaries || '（当前没有已有总结）'}`,
        },
        { role: 'user', content: source },
      ],
      {
        use_tavern_api: settings.use_tavern_api,
        api_endpoint: settings.api_endpoint,
        api_key: settings.api_key,
        model: settings.model,
        max_tokens: Math.max(512, Math.min(settings.max_tokens || 2048, 4096)),
        temperature: mode === 'natural' ? 0.35 : 0.7,
        top_p: settings.top_p,
        presence_penalty: settings.presence_penalty,
        frequency_penalty: settings.frequency_penalty,
      },
      { temperature: mode === 'natural' ? 0.35 : 0.7 },
    );
    previousDraft = input.value;
    setDraft(input, result);
    taskStore.addTaskDetail(taskId, `模式：${mode === 'natural' ? '自然润色' : '扩写细节'}`);
    taskStore.addTaskDetail(taskId, `参考：${context.visibleCount} 条可见消息 + ${context.summaries ? '已有总结' : '无总结'}`);
    taskStore.addTaskDetail(taskId, `字数：${source.length} → ${result.length}`);
    taskStore.completeTask(taskId, { mode, sourceLength: source.length, resultLength: result.length });
    window.toastr?.success('输入内容已润色，未自动发送');
  } catch (error) {
    console.error('输入润色失败:', error);
    const message = (error as Error).message;
    taskStore.failTask(taskId, message);
    window.toastr?.error(`输入润色失败：${message}`);
  } finally {
    activeRequest = false;
    updateControls();
  }
}

function updateControls() {
  const host = document.querySelector<HTMLElement>('#maomaomz-input-polisher');
  if (!host) return;
  const polish = host.querySelector<HTMLButtonElement>('[data-action="polish"]');
  const undo = host.querySelector<HTMLButtonElement>('[data-action="undo"]');
  if (polish) {
    polish.disabled = activeRequest;
    polish.innerHTML = activeRequest ? '<i class="fa-solid fa-spinner fa-spin"></i> 润色中' : '<i class="fa-solid fa-wand-magic-sparkles"></i> 润色';
  }
  if (undo) undo.disabled = activeRequest || !previousDraft;
}

function ensureControls() {
  const input = getInput();
  if (useSettingsStore().settings.input_polish_enabled === false) {
    document.querySelector('#maomaomz-input-polisher')?.remove();
    closeMenu();
    return;
  }
  if (!input || document.querySelector('#maomaomz-input-polisher')) return;

  const host = document.createElement('div');
  host.id = 'maomaomz-input-polisher';
  host.innerHTML = `
    <button type="button" data-action="polish" title="用 AI 润色当前输入，不会自动发送"><i class="fa-solid fa-wand-magic-sparkles"></i> 润色</button>
    <button type="button" data-action="undo" title="撤销上一次润色"><i class="fa-solid fa-rotate-left"></i></button>
  `;
  input.insertAdjacentElement('afterend', host);
  host.querySelector<HTMLButtonElement>('[data-action="polish"]')?.addEventListener('click', event => showMenu(event.currentTarget));
  host.querySelector<HTMLButtonElement>('[data-action="undo"]')?.addEventListener('click', () => {
    const currentInput = getInput();
    if (!currentInput || !previousDraft || activeRequest) return;
    setDraft(currentInput, previousDraft);
    previousDraft = '';
    updateControls();
    window.toastr?.info('已恢复润色前的输入内容');
  });
  updateControls();
}

function injectStyles() {
  if (document.querySelector('#maomaomz-input-polisher-style')) return;
  const style = document.createElement('style');
  style.id = 'maomaomz-input-polisher-style';
  style.textContent = `
    #maomaomz-input-polisher { display:flex; align-items:center; gap:6px; margin:4px 0 0; }
    #maomaomz-input-polisher button, #maomaomz-input-polisher-menu button { border:1px solid rgba(74,158,255,.45); border-radius:8px; background:rgba(45,108,178,.22); color:#b8d8ff; padding:5px 9px; font:inherit; font-size:12px; cursor:pointer; }
    #maomaomz-input-polisher button:hover, #maomaomz-input-polisher-menu button:hover { background:rgba(74,158,255,.35); }
    #maomaomz-input-polisher button:disabled { opacity:.55; cursor:wait; }
    #maomaomz-input-polisher-menu { position:fixed; z-index:10050; display:flex; gap:5px; padding:6px; border:1px solid rgba(255,255,255,.14); border-radius:10px; background:#25272c; box-shadow:0 8px 24px rgba(0,0,0,.38); }
  `;
  document.head.appendChild(style);
}

export function installInputPolisher() {
  injectStyles();
  ensureControls();
  if (!observer) {
    observer = new MutationObserver(() => ensureControls());
    observer.observe(document.body, { childList: true, subtree: true });
  }
  document.addEventListener('click', event => {
    const target = event.target as Element | null;
    if (!target?.closest('#maomaomz-input-polisher, #maomaomz-input-polisher-menu')) closeMenu();
  });
  window.addEventListener('maomaomz-input-polish-toggle', ensureControls);
  console.log('✨ 酒馆输入润色已安装');
}
