function getCandidateWindows(): Window[] {
  const windows: Window[] = [window];
  try {
    if (window.parent && window.parent !== window) windows.push(window.parent);
  } catch {
    // ignore cross-origin access errors
  }
  try {
    if (window.top && window.top !== window && window.top !== window.parent) windows.push(window.top);
  } catch {
    // ignore cross-origin access errors
  }
  return windows;
}

export function getSillyTavernRequestHeaders(): Record<string, string> {
  for (const win of getCandidateWindows()) {
    try {
      const st = (win as any).SillyTavern ?? (globalThis as any).SillyTavern;
      const ctx = typeof st?.getContext === 'function' ? st.getContext() : null;
      const headers =
        (typeof ctx?.getRequestHeaders === 'function' ? ctx.getRequestHeaders() : null) ??
        (typeof st?.getRequestHeaders === 'function' ? st.getRequestHeaders() : null);
      if (headers && typeof headers === 'object') return headers;
    } catch (e) {
      console.warn('获取 SillyTavern 请求头失败:', e);
    }
  }
  return {};
}
