/**
 * 统一的「总结世界书」名称解析。
 *
 * 之前手动创建用「总结_角色_日期」，自动总结用「总结_角色_聊天ID尾段」，两套命名导致
 * 同一个聊天反复创建出多本世界书、互相不认识。这里统一规则：
 *
 * 1) 如果当前聊天已经绑定了世界书，直接复用它（最高优先级）。
 * 2) 否则用「总结_角色名_聊天ID尾段」作为稳定名称（按聊天档隔离，同一聊天永远同名）。
 *
 * 所有需要"找/建总结世界书"的地方都应调用这里，避免重复创建。
 */

import { getChatIdSafe } from '../utils';
import { getSillyTavernRequestHeaders } from './sillytavern-headers';

/** 获取当前角色名（已清理非法字符） */
function getSafeCharacterName(): string {
  try {
    const TH = (window as any).TavernHelper;
    const currentCharacter = TH?.getCharData?.('current');
    if (currentCharacter?.name) {
      return String(currentCharacter.name).replace(/[<>:"/\\|?*]/g, '_').trim() || '未知角色';
    }
  } catch (e) {
    console.warn('获取角色信息失败:', e);
  }
  return '未知角色';
}

/** 把聊天 ID / 聊天文件名归一化成世界书命名用的尾段（去扩展名、取尾 8 位） */
function toShortChatId(chatIdOrFile: string): string {
  const chatId = String(chatIdOrFile || '')
    .replace(/\.jsonl$/i, '')
    .trim();
  if (!chatId) return 'default';
  return chatId.length > 8 ? chatId.slice(-8) : chatId;
}

/** 计算当前聊天对应的稳定世界书名（不含"是否已绑定"判断） */
export function getStableSummaryWorldbookName(): string {
  const characterName = getSafeCharacterName();
  const chatId = getChatIdSafe() || 'default';
  return `总结_${characterName}_${toShortChatId(chatId)}`;
}

/**
 * 删除某个聊天对应的「总结世界书」整本。
 *
 * 用于聊天被删除时清理残留：插件的总结世界书是按「总结_角色_聊天ID尾段」单独建的整本世界书，
 * 酒馆删聊天时不会连带删除它，所以需要插件自己监听 CHAT_DELETED 主动删。
 *
 * @param chatFileName 被删除聊天的文件名 / 聊天 ID；为空时回退到当前聊天 ID。
 * @returns 实际删除掉的世界书名列表。
 */
export async function deleteSummaryWorldbookForChat(chatFileName?: string): Promise<string[]> {
  const TH = (window as any).TavernHelper;
  if (!TH || typeof TH.deleteWorldbook !== 'function') return [];

  const shortChatId = toShortChatId(chatFileName || getChatIdSafe() || '');
  if (!shortChatId || shortChatId === 'default') return [];

  // 当前角色名对应的精确命名
  const exactName = `总结_${getSafeCharacterName()}_${shortChatId}`;
  const suffix = `_${shortChatId}`;

  let existing: string[] = [];
  try {
    existing = TH.getWorldbookNames?.() || [];
  } catch (e) {
    console.warn('获取世界书列表失败:', e);
  }

  // 只删插件自己建的「总结_…_聊天ID尾段」整本，避免误删用户世界书
  const targets = existing.filter(
    name => name === exactName || (typeof name === 'string' && name.startsWith('总结_') && name.endsWith(suffix)),
  );

  const deleted: string[] = [];
  for (const name of targets) {
    try {
      const ok = await TH.deleteWorldbook(name);
      if (ok !== false) {
        deleted.push(name);
        console.log(`🗑️ 已随聊天删除残留的总结世界书: ${name}`);
      }
    } catch (e) {
      console.warn(`删除总结世界书「${name}」失败:`, e);
    }
  }
  return deleted;
}

/**
 * 删除「指定楼层范围相关」的插件总结条目。
 *
 * 用于：用户删楼层 / roll 重生成后，把那些「结束楼层 >= 被改动楼层」的旧总结条目清掉，
 * 避免旧总结和新剧情对不上。只在「当前聊天绑定的世界书」和「插件稳定命名的总结书」里删，
 * 绝不碰角色卡附加知识书。
 *
 * @param fromFloor 从这一楼层（含）起，凡是结束楼层 >= fromFloor 的总结条目都删
 *                  （即跨越或晚于删除点、包含了已改动楼层的总结）。
 * @returns 是否发生了删除。
 */
export async function deleteSummaryEntriesFromFloor(fromFloor: number): Promise<boolean> {
  const TH = (window as any).TavernHelper;
  if (!TH || typeof TH.deleteWorldbookEntries !== 'function') return false;

  const candidates = new Set<string>();
  try {
    const chatWb = TH.getChatWorldbookName?.('current');
    if (chatWb) candidates.add(chatWb);
  } catch {
    /* ignore */
  }
  candidates.add(getStableSummaryWorldbookName());

  // 从条目名「总结_楼层X-Y」或「大总结_楼层X-Y」解析结束楼层 Y
  const parseEnd = (entry: any): number | null => {
    const m = typeof entry?.name === 'string' ? entry.name.match(/^(?:大)?总结_楼层\d+-(\d+)$/) : null;
    if (m) return parseInt(m[1], 10);
    const c = typeof entry?.comment === 'string' ? entry.comment.match(/楼层范围:\s*\d+\s*-\s*(\d+)/) : null;
    if (c) return parseInt(c[1], 10);
    return null;
  };

  // 是否为插件自己创建的总结条目（含小总结与大总结）
  const isPluginSummaryEntry = (entry: any): boolean =>
    entry?.extra?.maomaomz_summary === true ||
    entry?.extra?.maomaomz_mega_summary === true ||
    (typeof entry?.name === 'string' && /^(?:大)?总结_楼层\d+-\d+$/.test(entry.name)) ||
    (typeof entry?.comment === 'string' &&
      (entry.comment.includes('自动生成的总结条目') || entry.comment.includes('自动生成的大总结条目')));

  // 只删插件自己创建的总结条目（含大总结），且「结束楼层 >= fromFloor」——
  // 即凡是跨越或晚于被改动楼层的总结都要删（例如删第14层时，楼层10-14 这条也要删，
  // 大总结_楼层0-24 也要删，因为它总结了已不存在的第14层，属于脏数据）。
  const matcher = (entry: any) => {
    if (!isPluginSummaryEntry(entry)) return false;
    const end = parseEnd(entry);
    return end !== null && end >= fromFloor;
  };

  let deleted = false;
  for (const wbName of candidates) {
    if (!wbName) continue;
    try {
      const res = await TH.deleteWorldbookEntries(wbName, matcher);
      if (res?.delete_occurred || res?.deleted_entries?.length) deleted = true;
    } catch (e) {
      console.warn(`删除世界书「${wbName}」中起始楼层>=${fromFloor}的总结条目失败:`, e);
    }
  }
  if (deleted) console.log(`✅ 已删除结束楼层 >= ${fromFloor} 的总结世界书条目`);

  // 删掉脏大总结后，重新启用「结束楼层 < fromFloor」但被大总结关掉的小总结，
  // 否则删楼层后既没了大总结、这些仍然有效的小总结又是关闭状态，记忆会断层。
  if (typeof TH.updateWorldbookWith === 'function') {
    for (const wbName of candidates) {
      if (!wbName) continue;
      try {
        await TH.updateWorldbookWith(wbName, (worldbook: any[]) => {
          for (const entry of worldbook) {
            const isSmall =
              entry?.extra?.maomaomz_summary === true ||
              (typeof entry?.name === 'string' && /^总结_楼层\d+-\d+$/.test(entry.name));
            if (!isSmall || entry?.enabled !== false) continue;
            const end = parseEnd(entry);
            if (end !== null && end < fromFloor) {
              entry.enabled = true;
              console.log(`👁️ 删楼层后重新启用仍有效的小总结条目: ${entry.name}`);
            }
          }
          return worldbook;
        });
      } catch (e) {
        console.warn(`重新启用世界书「${wbName}」中有效小总结失败:`, e);
      }
    }
  }

  return deleted;
}

/**
 * 清理「孤儿总结世界书」：删掉那些不再对应任何现存聊天的 `总结_当前角色_尾段` 整本世界书。
 *
 * 为什么不只靠 CHAT_DELETED 事件：实测有些酒馆版本删聊天时不会把事件派发到插件，
 * 导致残留世界书越积越多。这里改为主动核对——拉取当前角色的全部聊天文件，算出有效的
 * 「聊天ID尾段」集合，凡是当前角色名下、尾段不在该集合里的总结世界书，判定为孤儿并删除。
 *
 * 只处理「当前角色」名下、且尾段格式像聊天时间戳的总结书，绝不碰别的角色或用户自己的世界书。
 *
 * @returns 实际删除的世界书名列表
 */
export async function cleanupOrphanSummaryWorldbooks(): Promise<string[]> {
  const TH = (window as any).TavernHelper;
  if (!TH || typeof TH.deleteWorldbook !== 'function') return [];

  const characterName = getSafeCharacterName();
  if (!characterName || characterName === '未知角色') {
    console.log('🧹 孤儿清理：拿不到当前角色名，跳过');
    return [];
  }

  // 1) 拿当前角色的全部聊天文件名
  let chatFiles: string[] = [];
  try {
    chatFiles = await fetchCurrentCharacterChatFiles();
  } catch (e) {
    console.warn('获取角色聊天列表失败，跳过孤儿世界书清理:', e);
    return [];
  }
  console.log(`🧹 孤儿清理：角色「${characterName}」现存聊天 ${chatFiles.length} 个:`, chatFiles);
  // 拿不到聊天列表时不敢删（避免误删），直接返回
  if (!chatFiles.length) {
    console.log('🧹 孤儿清理：聊天列表为空，保守起见不删除任何世界书');
    return [];
  }

  // 2) 有效尾段集合（含当前聊天，双保险）
  const validSuffixes = new Set<string>();
  for (const f of chatFiles) validSuffixes.add(toShortChatId(f));
  const currentChatId = getChatIdSafe();
  if (currentChatId) validSuffixes.add(toShortChatId(currentChatId));
  console.log('🧹 孤儿清理：有效聊天尾段集合:', Array.from(validSuffixes));

  // 3) 当前聊天已绑定的世界书绝不动
  let boundName = '';
  try {
    boundName = TH.getChatWorldbookName?.('current') || '';
  } catch {
    /* ignore */
  }

  // 4) 找出当前角色名下的总结世界书，尾段不在有效集合里的就是孤儿
  let existing: string[] = [];
  try {
    existing = TH.getWorldbookNames?.() || [];
  } catch (e) {
    console.warn('获取世界书列表失败:', e);
    return [];
  }

  const prefix = `总结_${characterName}_`;
  const candidates = existing.filter(n => typeof n === 'string' && n.startsWith(prefix));
  console.log(`🧹 孤儿清理：角色名下总结世界书 ${candidates.length} 本:`, candidates);
  const deleted: string[] = [];
  for (const name of existing) {
    if (typeof name !== 'string') continue;
    if (name === boundName) continue;
    if (!name.startsWith(prefix)) continue;
    const suffix = name.slice(prefix.length);
    // 尾段必须像聊天时间戳尾段（避免误删用户手动命名的「总结_角色_xxx」）
    if (!/^[0-9a-zA-Z@\-]{2,}$/.test(suffix)) continue;
    if (validSuffixes.has(suffix)) continue; // 对应聊天还在，保留

    try {
      const ok = await TH.deleteWorldbook(name);
      if (ok !== false) {
        deleted.push(name);
        console.log(`🗑️ 已清理孤儿总结世界书（无对应聊天）: ${name}`);
      }
    } catch (e) {
      console.warn(`删除孤儿总结世界书「${name}」失败:`, e);
    }
  }
  return deleted;
}

/** 通过 SillyTavern 后端接口获取「当前角色」的全部聊天文件名（去扩展名前的原始名） */
async function fetchCurrentCharacterChatFiles(): Promise<string[]> {
  const st: any = typeof SillyTavern !== 'undefined' ? SillyTavern : (window as any).SillyTavern;
  if (!st) return [];

  // 找到当前角色的 avatar（聊天列表接口需要 avatar_url）
  let avatar = '';
  try {
    const ctx = typeof st.getContext === 'function' ? st.getContext() : st;
    const chars = ctx.characters || st.characters || [];
    const charId = ctx.characterId ?? st.characterId;
    if (charId != null && chars[charId]) {
      avatar = chars[charId].avatar;
    } else {
      const TH = (window as any).TavernHelper;
      const cur = TH?.getCharData?.('current');
      if (cur?.avatar) avatar = cur.avatar;
    }
  } catch (e) {
    console.warn('获取当前角色 avatar 失败:', e);
  }
  if (!avatar) {
    console.warn('🧹 孤儿清理：拿不到当前角色 avatar，无法查询聊天列表');
    return [];
  }
  console.log('🧹 孤儿清理：当前角色 avatar =', avatar);

  const headers = {
    'Content-Type': 'application/json',
    ...getSillyTavernRequestHeaders(),
  };

  const res = await fetch('/api/characters/chats', {
    method: 'POST',
    headers,
    body: JSON.stringify({ avatar_url: avatar, simple: true }),
  });
  if (!res.ok) throw new Error(`聊天列表接口返回 ${res.status}`);
  const data = await res.json();

  // 返回结构通常是数组，每项含 file_name（形如 "角色 - 2026-...@..s..ms.jsonl"）
  const files: string[] = [];
  if (Array.isArray(data)) {
    for (const item of data) {
      const fn = item?.file_name || item?.file || (typeof item === 'string' ? item : '');
      if (fn) files.push(String(fn));
    }
  } else if (data && typeof data === 'object') {
    for (const key of Object.keys(data)) {
      const fn = data[key]?.file_name || key;
      if (fn) files.push(String(fn));
    }
  }
  return files;
}

/**
 * 解析当前聊天应使用的总结世界书：优先复用已绑定的，没有则返回稳定名称。
 * 不会创建世界书，只返回名字与是否已存在/已绑定。
 */
export function resolveSummaryWorldbookName(): { name: string; isBound: boolean } {
  const TH = (window as any).TavernHelper;
  // 1) 复用当前聊天已绑定的世界书
  try {
    const bound = TH?.getChatWorldbookName?.('current');
    if (bound) return { name: bound, isBound: true };
  } catch (e) {
    console.warn('获取当前聊天绑定世界书失败:', e);
  }
  // 2) 稳定命名
  return { name: getStableSummaryWorldbookName(), isBound: false };
}

/**
 * 确保当前聊天有可用的总结世界书并已绑定，返回世界书名。
 * - 已绑定：直接返回。
 * - 未绑定但同名已存在：绑定后返回。
 * - 都没有：创建 + 绑定后返回。
 */
export async function ensureSummaryWorldbook(): Promise<string> {
  const TH = (window as any).TavernHelper;
  if (!TH) throw new Error('TavernHelper 不可用');

  const resolved = resolveSummaryWorldbookName();
  if (resolved.isBound) return resolved.name;

  const worldbookName = resolved.name;

  // 检查同名是否已存在
  let existing: string[] = [];
  try {
    existing = TH.getWorldbookNames?.() || [];
  } catch (e) {
    console.warn('获取世界书列表失败:', e);
  }

  if (!existing.includes(worldbookName)) {
    await TH.createWorldbook?.(worldbookName, []);
  }

  // 绑定到当前聊天
  try {
    await TH.rebindChatWorldbook?.('current', worldbookName);
  } catch (bindError) {
    console.warn('绑定世界书到聊天失败:', bindError);
  }

  return worldbookName;
}
